var surah012 = {
  number: 12,
  nameArabic: "Yusuf",
  nameEnglish: "Yusuf",
  meaning: "Joseph",
  totalAyahs: 111,
  ayahs: [
    { number: 1, arabic: "الٓر ۚ تِلْكَ ءَايَٰتُ ٱلْكِتَٰبِ ٱلْمُبِينِ", transliteration: "Aliflamra tilka ayatu alkitabi almubeenu", transliterationB: "Alif-Laaam-Raa; tilka Aayaatul Kitaabil Mubeen", english: "L. R. These are the symbols (or Verses) of the perspicuous Book", romanUrdu: "Alif, Laam, Raa .. Yeh us kitab ki aayat hain jo apna muddua (its object) saaf saaf bayan karti hai" },
    { number: 2, arabic: "إِنَّآ أَنزَلْنَٰهُ قُرْءَٰنًا عَرَبِيًّۭا لَّعَلَّكُمْ تَعْقِلُونَ", transliteration: "Inna anzalnahu quranan AAarabiyyan laAAallakum taAAqiloona", transliterationB: "Innaaa anzalnaahu quraanan 'Arabiyyal la 'allakum ta'qiloon", english: "We have sent it down as an Arabic Qur'an, in order that ye may learn wisdom", romanUrdu: "Humne isey nazil kiya hai Quran bana kar arabi zubaan mein taa-ke tum (ehle arab) isko acchi tarah samajh sako" },
    { number: 3, arabic: "نَحْنُ نَقُصُّ عَلَيْكَ أَحْسَنَ ٱلْقَصَصِ بِمَآ أَوْحَيْنَآ إِلَيْكَ هَٰذَا ٱلْقُرْءَانَ وَإِن كُنتَ مِن قَبْلِهِۦ لَمِنَ ٱلْغَٰفِلِينَ", transliteration: "Nahnu naqussu AAalayka ahsana alqasasi bima awhayna ilayka hatha alqurana wain kunta min qablihi lamina alghafileena", transliterationB: "Nahnu naqussu 'alaika ahsanal qasasi bimaaa awhainaaa ilaika haazal quraana wa in kunta min qablihee laminal ghaafileen", english: "We do relate unto thee the most beautiful of stories, in that We reveal to thee this (portion of the) Qur'an: before this, thou too was among those who knew it not", romanUrdu: "(Aey Muhammad), hum is Quran ko tumhari taraf wahee karke behtareen pairaye mein waqiyaat aur haqaiq tumse bayaan karte hain, warna issey pehle to (in cheezon se) tum bilkul hi be-khabar thay" },
    { number: 4, arabic: "إِذْ قَالَ يُوسُفُ لِأَبِيهِ يَٰٓأَبَتِ إِنِّى رَأَيْتُ أَحَدَ عَشَرَ كَوْكَبًۭا وَٱلشَّمْسَ وَٱلْقَمَرَ رَأَيْتُهُمْ لِى سَٰجِدِينَ", transliteration: "Ith qala yoosufu liabeehi ya abati innee raaytu ahada AAashara kawkaban waalshshamsa waalqamara raaytuhum lee sajideena", transliterationB: "Iz qaala Yoosufu li abeehi yaaa abati innee ra aytu ahada 'ashara kawkabanw wash shamsa walqamara ra aytuhum lee saajideen", english: "Behold! Joseph said to his father: \"O my father! I did see eleven stars and the sun and the moon: I saw them prostrate themselves to me", romanUrdu: "Yeh us waqt ka zikr hai jab Yusuf ne apne baap se kaha “abbajaan , maine khwab dekha hai ke gyarah(eleven) sitarey hain aur Suraj aur Chand hain aur woh mujhey sajda kar rahey hain”" },
    { number: 5, arabic: "قَالَ يَٰبُنَىَّ لَا تَقْصُصْ رُءْيَاكَ عَلَىٰٓ إِخْوَتِكَ فَيَكِيدُوا۟ لَكَ كَيْدًا ۖ إِنَّ ٱلشَّيْطَٰنَ لِلْإِنسَٰنِ عَدُوٌّۭ مُّبِينٌۭ", transliteration: "Qala ya bunayya la taqsus ruyaka AAala ikhwatika fayakeedoo laka kaydan inna alshshaytana lilinsani AAaduwwun mubeenun", transliterationB: "Qaala yaa bunaiya laa taqsus ru'yaaka 'alaaa ikhwatika fayakeedoo laka kaidaa; innash Shaitaana lil insaani 'aduwwum mubeen", english: "Said (the father): \"My (dear) little son! relate not thy vision to thy brothers, lest they concoct a plot against thee: for Satan is to man an avowed enemy", romanUrdu: "Jawab mein uke baap ne kaha, “beta, apna yeh khwab apne bhaiyon ko na sunana warna woh tere darpe azar ho jayenge(plot any evil scheme against you), haqeeqat yeh hai ke shaytan aadmi ka khula dushman hai" },
    { number: 6, arabic: "وَكَذَٰلِكَ يَجْتَبِيكَ رَبُّكَ وَيُعَلِّمُكَ مِن تَأْوِيلِ ٱلْأَحَادِيثِ وَيُتِمُّ نِعْمَتَهُۥ عَلَيْكَ وَعَلَىٰٓ ءَالِ يَعْقُوبَ كَمَآ أَتَمَّهَا عَلَىٰٓ أَبَوَيْكَ مِن قَبْلُ إِبْرَٰهِيمَ وَإِسْحَٰقَ ۚ إِنَّ رَبَّكَ عَلِيمٌ حَكِيمٌۭ", transliteration: "Wakathalika yajtabeeka rabbuka wayuAAallimuka min taweeli alahadeethi wayutimmu niAAmatahu AAalayka waAAala ali yaAAqooba kama atammaha AAala abawayka min qablu ibraheema waishaqa inna rabbaka AAaleemun hakeemun", transliterationB: "Wa kazaalika yajtabeeka rabbuka wa yu'allimuka min taaweelil ahaadeesi wa yutimmu ni'matahoo 'alaika wa 'alaaa Aali Ya'qooba kamaaa atammahaa 'alaaa abawaika min qablu Ibraaheema wa Ishaaq; inna Rabbaka 'Aleemun hakeem", english: "Thus will thy Lord choose thee and teach thee the interpretation of stories (and events) and perfect His favour to thee and to the posterity of Jacob - even as He perfected it to thy fathers Abraham and Isaac aforetime! for Allah is full of knowledge and wisdom", romanUrdu: "Aur aisa hi hoga (jaisa tu nay khwab mein dekha hai ke) tera Rubb tujhey (apne kaam ke liye) muntakhab(choose) karega aur tumhey baaton ki teh tak pahunchna sikhayega aur tere upar aur aale Yaqub par apni niyamat usi tarah poori karega jis tarah issey pehle woh tere buzurgon , Ibrahim aur Ishaq par kar chuka hai, yaqeenan tera Rubb aleem (All-Knowing)-o-hakeem hai (All-Wise)”" },
    { number: 7, arabic: "۞ لَّقَدْ كَانَ فِى يُوسُفَ وَإِخْوَتِهِۦٓ ءَايَٰتٌۭ لِّلسَّآئِلِينَ", transliteration: "Laqad kana fee yoosufa waikhwatihi ayatun lilssaileena", transliterationB: "Laqad kaana fee Yoosufa wa ikhwatiheee Aayaatul lissaaa'ileen", english: "Verily in Joseph and his brethren are signs (or symbols) for seekers (after Truth)", romanUrdu: "Haqeeqat yeh hai ke Yusuf aur uske bhaiyon ke qissey mein in poochne walon ke liye badi nishaniyan hain" },
    { number: 8, arabic: "إِذْ قَالُوا۟ لَيُوسُفُ وَأَخُوهُ أَحَبُّ إِلَىٰٓ أَبِينَا مِنَّا وَنَحْنُ عُصْبَةٌ إِنَّ أَبَانَا لَفِى ضَلَٰلٍۢ مُّبِينٍ", transliteration: "Ith qaloo layoosufu waakhoohu ahabbu ila abeena minna wanahnu AAusbatun inna abana lafee dalalin mubeenin", transliterationB: "Iz qaaloo la Yoosufu wa akhoohu ahabbu ilaaa Abeenaa minnaa wa nahnu 'usbah; inna abaanaa lafee dalaalim mubeen", english: "They said: \"Truly Joseph and his brother are loved more by our father than we: But we are a goodly body! really our father is obviously wandering (in his mind)", romanUrdu: "Yeh qissa yun shuru hota hai ke uske bhaiyon ne aapas mein kaha “yeh Yusuf aur iska bhai, dono hamare walid(baap) ko hum sab se zyada mehboob hai halanke hum ek pura jattha (band) hain. Sacchi baat yeh hai ke hamare abbajaan bilkul hi behak gaye hain" },
    { number: 9, arabic: "ٱقْتُلُوا۟ يُوسُفَ أَوِ ٱطْرَحُوهُ أَرْضًۭا يَخْلُ لَكُمْ وَجْهُ أَبِيكُمْ وَتَكُونُوا۟ مِنۢ بَعْدِهِۦ قَوْمًۭا صَٰلِحِينَ", transliteration: "Oqtuloo yoosufa awi itrahoohu ardan yakhlu lakum wajhu abeekum watakoonoo min baAAdihi qawman saliheena", transliterationB: "Uqtuloo Yoosufa awitra hoohu ardany yakhlu lakum wajhu abeekum wa takoonoo mim ba'dihee qawman saaliheen", english: "Slay ye Joseph or cast him out to some (unknown) land, that so the favour of your father may be given to you alone: (there will be time enough) for you to be righteous after that", romanUrdu: "Chalo Yusuf ko qatal kardo ya usey kahin phenk do taa-ke tumhare walid ki tawajju (attention) sirf tumhari hi taraf ho jaye. Yeh kaam kar lene ke baad phir neik ban rehna”" },
    { number: 10, arabic: "قَالَ قَآئِلٌۭ مِّنْهُمْ لَا تَقْتُلُوا۟ يُوسُفَ وَأَلْقُوهُ فِى غَيَٰبَتِ ٱلْجُبِّ يَلْتَقِطْهُ بَعْضُ ٱلسَّيَّارَةِ إِن كُنتُمْ فَٰعِلِينَ", transliteration: "Qala qailun minhum la taqtuloo yoosufa waalqoohu fee ghayabati aljubbi yaltaqithu baAAdu alssayyarati in kuntum faAAileena", transliterationB: "Qaalaa qaaa'ilum minhum laa taqtuloo Yoosufa wa alqoohu fee ghayaabatil jubbi yaltaqithu badus sai yaarati in kuntum faa 'ileen", english: "Said one of them: \"Slay not Joseph, but if ye must do something, throw him down to the bottom of the well: he will be picked up by some caravan of travellers", romanUrdu: "Ispar un mein se ek bola “Yusuf ko qatal na karo, agar kuch karna hi hai to usey kisi andhey kuwein (well) mein daal do. Koi aata jata kafila (caravan) usey nikal le jayega”" },
    { number: 11, arabic: "قَالُوا۟ يَٰٓأَبَانَا مَا لَكَ لَا تَأْمَ۫نَّا عَلَىٰ يُوسُفَ وَإِنَّا لَهُۥ لَنَٰصِحُونَ", transliteration: "Qaloo ya abana ma laka la tamanna AAala yoosufa wainna lahu lanasihoona", transliterationB: "Qaaloo yaaa abaanaa maa laka laa taamannaa 'alaa Yoosufa wa innaa lahoo lanaa sihoon", english: "They said: \"O our father! why dost thou not trust us with Joseph,- seeing we are indeed his sincere well-wishers", romanUrdu: "Is qarardaad par unhon ne jaa kar apne baap se kaha, “abbajaan, kya baat hai ke aap Yusuf ke maamle mein humpar bharosa nahin karte halanke hum uske sacchey khair-khwa (well wishers)hain" },
    { number: 12, arabic: "أَرْسِلْهُ مَعَنَا غَدًۭا يَرْتَعْ وَيَلْعَبْ وَإِنَّا لَهُۥ لَحَٰفِظُونَ", transliteration: "Arsilhu maAAana ghadan yartaAA wayalAAab wainna lahu lahafithoona", transliterationB: "Arilhu ma'anaa ghadany yarta'wa yal'ab wa innaa lahoo lahaafizoon", english: "Send him with us tomorrow to enjoy himself and play, and we shall take every care of him", romanUrdu: "Kal usey hamare saath bhej dijiye, kuch char-chug (freely eat) lega aur khel-kood se bhi dil behlayega, hum uski hifazat ko maujood hain”" },
    { number: 13, arabic: "قَالَ إِنِّى لَيَحْزُنُنِىٓ أَن تَذْهَبُوا۟ بِهِۦ وَأَخَافُ أَن يَأْكُلَهُ ٱلذِّئْبُ وَأَنتُمْ عَنْهُ غَٰفِلُونَ", transliteration: "Qala innee layahzununee an thathhaboo bihi waakhafu an yakulahu alththibu waantum AAanhu ghafiloona", transliterationB: "Qaala innee la yahzununeee an tazhaboo bihee wa akhaafu anyyaakulahuz zi'bu wa antum 'anhu ghaafiloon", english: "(Jacob) said: \"Really it saddens me that ye should take him away: I fear lest the wolf should devour him while ye attend not to him", romanUrdu: "Baap ne kaha “tumhara isey le jana mujhey shaaq guzarta hai(troubles me) aur mujhko andesha hai ke kahin isey bhediya (wolf) na phaad khaye jabke tum issey gaafil ho”" },
    { number: 14, arabic: "قَالُوا۟ لَئِنْ أَكَلَهُ ٱلذِّئْبُ وَنَحْنُ عُصْبَةٌ إِنَّآ إِذًۭا لَّخَٰسِرُونَ", transliteration: "Qaloo lain akalahu alththibu wanahnu AAusbatun inna ithan lakhasiroona", transliterationB: "Qaaloo la in akalahuzzi'bu wa nahnu 'usbatun innaaa izal lakhaasiroon", english: "They said: \"If the wolf were to devour him while we are (so large) a party, then should we indeed (first) have perished ourselves", romanUrdu: "Unhon ne jawab diya, “agar hamare hotey isey bhediye (wolf) ne kha liya, jabke hum ek jattha (band) hain, tab to hum badey hi nikamme hongey”" },
    { number: 15, arabic: "فَلَمَّا ذَهَبُوا۟ بِهِۦ وَأَجْمَعُوٓا۟ أَن يَجْعَلُوهُ فِى غَيَٰبَتِ ٱلْجُبِّ ۚ وَأَوْحَيْنَآ إِلَيْهِ لَتُنَبِّئَنَّهُم بِأَمْرِهِمْ هَٰذَا وَهُمْ لَا يَشْعُرُونَ", transliteration: "Falamma thahaboo bihi waajmaAAoo an yajAAaloohu fee ghayabati aljubbi waawhayna ilayhi latunabiannahum biamrihim hatha wahum la yashAAuroona", transliterationB: "Falammaa zahaboo bihee wa ajma'ooo anyyaj'aloohu fee ghayaabatil jubb; wa awyainaaa ilaihi latunabbi 'annahum bi amrihim haaza wa hum laa yash'uroon", english: "So they did take him away, and they all agreed to throw him down to the bottom of the well: and We put into his heart (this Message): 'Of a surety thou shalt (one day) tell them the truth of this their affair while they know (thee) not", romanUrdu: "Is tarah israr karke jab woh usey le gaye aur unhon ne tai kar liya ke usey ek andhey kuwein (well) mein chodh dein, to humne Yusuf ko wahee(revelation) ki ke “ek waqt aayega jab tu in logon ko inki yeh harakat jatayega , yeh apne fail ke nataij se be khabar hain”" },
    { number: 16, arabic: "وَجَآءُوٓ أَبَاهُمْ عِشَآءًۭ يَبْكُونَ", transliteration: "Wajaoo abahum AAishaan yabkoona", transliterationB: "Wa jaaa'ooo abaahum 'ishaaa 'any yabkoon", english: "Then they came to their father in the early part of the night, weeping", romanUrdu: "Shaam ko woh rotey peeth-te (wailing) apne baap ke paas aaye" },
    { number: 17, arabic: "قَالُوا۟ يَٰٓأَبَانَآ إِنَّا ذَهَبْنَا نَسْتَبِقُ وَتَرَكْنَا يُوسُفَ عِندَ مَتَٰعِنَا فَأَكَلَهُ ٱلذِّئْبُ ۖ وَمَآ أَنتَ بِمُؤْمِنٍۢ لَّنَا وَلَوْ كُنَّا صَٰدِقِينَ", transliteration: "Qaloo ya abana inna thahabna nastabiqu watarakna yoosufa AAinda mataAAina faakalahu alththibu wama anta bimuminin lana walaw kunna sadiqeena", transliterationB: "Qaaloo yaaa abaanaaa innaa zahabnaa nastabiqu wa taraknaa Yoosufa 'inda mataa'inaa fa akhalahuz zi'b, wa maaa anta bimu'minil lanaa wa law kunnaa saadiqeen", english: "They said: \"O our father! We went racing with one another, and left Joseph with our things; and the wolf devoured him.... But thou wilt never believe us even though we tell the truth", romanUrdu: "Aur kaha “abbajaan, hum daud (running) ka muqabla karne mein lag gaye thay aur Yusuf ko humne apne samaan ke paas chodh diya tha ke itne mein bhediya (wolf) aakar usey kha gaya. Aap hamari baat ka yaqeen na karenge chahe hum sacchey hi hon”" },
    { number: 18, arabic: "وَجَآءُو عَلَىٰ قَمِيصِهِۦ بِدَمٍۢ كَذِبٍۢ ۚ قَالَ بَلْ سَوَّلَتْ لَكُمْ أَنفُسُكُمْ أَمْرًۭا ۖ فَصَبْرٌۭ جَمِيلٌۭ ۖ وَٱللَّهُ ٱلْمُسْتَعَانُ عَلَىٰ مَا تَصِفُونَ", transliteration: "Wajaoo AAala qameesihi bidamin kathibin qala bal sawwalat lakum anfusukum amran fasabrun jameelun waAllahu almustaAAanu AAala ma tasifoona", transliterationB: "Wa jaaa'oo 'alaa qamee shihee bidamin kazi' qaala bal sawwalat lakum anfusukum amraa; fasabrun jameel; wallaahul musta'aanu 'alaa man tasifoon", english: "They stained his shirt with false blood. He said: \"Nay, but your minds have made up a tale (that may pass) with you, (for me) patience is most fitting: Against that which ye assert, it is Allah (alone) Whose help can be sought", romanUrdu: "Aur woh Yusuf ke kamees (shirt) par jhoot moot ka khoon laga kar lay aaye thay. Yeh sunkar unke baap ne kaha “balke tumhare nafs ne tumhare liye ek baday kaam ko aasaan bana diya. Accha sabr karunga aur bakhubi karunga. Jo baat tum bana rahey ho uspar Allah hi se madad maangi jaa sakti hai.”" },
    { number: 19, arabic: "وَجَآءَتْ سَيَّارَةٌۭ فَأَرْسَلُوا۟ وَارِدَهُمْ فَأَدْلَىٰ دَلْوَهُۥ ۖ قَالَ يَٰبُشْرَىٰ هَٰذَا غُلَٰمٌۭ ۚ وَأَسَرُّوهُ بِضَٰعَةًۭ ۚ وَٱللَّهُ عَلِيمٌۢ بِمَا يَعْمَلُونَ", transliteration: "Wajaat sayyaratun faarsaloo waridahum faadla dalwahu qala ya bushra hatha ghulamun waasarroohu bidaAAatan waAllahu AAaleemun bima yaAAmaloona", transliterationB: "Wa jaaa'at saiyaaratun fa-arsaloo waaridahum fa adlaa dalwah; qaala yaa bushraa haaza ghulaam; wa asarroohu bi-daa'ah; wallaahu 'aleemum bimaa ya'maloon", english: "Then there came a caravan of travellers: they sent their water-carrier (for water), and he let down his bucket (into the well)... He said: \"Ah there! Good news! Here is a (fine) young man!\" So they concealed him as a treasure! But Allah knoweth well all that they do", romanUrdu: "Udhar ek kafila aaya aur usne apne saqqe (water carrier) ko pani laney ke liye bheja. Saqqe(water carrier) ne jo kuwein mein dol (bucket) dala to (Yusuf ko dekh kar) pukar uttha “mubarak ho! yahan to ek ladka hai”. Un logon ne usko maal e tijarat samajh kar chupa liya, halanke jo kuch woh kar rahey thay khuda ussey bakhabar tha" },
    { number: 20, arabic: "وَشَرَوْهُ بِثَمَنٍۭ بَخْسٍۢ دَرَٰهِمَ مَعْدُودَةٍۢ وَكَانُوا۟ فِيهِ مِنَ ٱلزَّٰهِدِينَ", transliteration: "Washarawhu bithamanin bakhsin darahima maAAdoodatin wakanoo feehi mina alzzahideena", transliterationB: "Wa sharawhu bisamanim bakhsin daraahima ma'doo datinw wa kaanoo feehi minaz zaahideen", english: "The (Brethren) sold him for a miserable price, for a few dirhams counted out: in such low estimation did they hold him", romanUrdu: "Aakhir e kaar unhon ne usko thodi si keemat par chandh dirhamo ke evaz bech daala aur woh uski keemat ke maamle mein kuch zyada ke ummedwaar na thay" },
    { number: 21, arabic: "وَقَالَ ٱلَّذِى ٱشْتَرَىٰهُ مِن مِّصْرَ لِٱمْرَأَتِهِۦٓ أَكْرِمِى مَثْوَىٰهُ عَسَىٰٓ أَن يَنفَعَنَآ أَوْ نَتَّخِذَهُۥ وَلَدًۭا ۚ وَكَذَٰلِكَ مَكَّنَّا لِيُوسُفَ فِى ٱلْأَرْضِ وَلِنُعَلِّمَهُۥ مِن تَأْوِيلِ ٱلْأَحَادِيثِ ۚ وَٱللَّهُ غَالِبٌ عَلَىٰٓ أَمْرِهِۦ وَلَٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَعْلَمُونَ", transliteration: "Waqala allathee ishtarahu min misra liimraatihi akrimee mathwahu AAasa an yanfaAAana aw nattakhithahu waladan wakathalika makkanna liyoosufa fee alardi walinuAAallimahu min taweeli alahadeethi waAllahu ghalibun AAala amrihi walakinna akthara alnnasi la yaAAlamoona", transliterationB: "Wa qaalal lazish taraahu mim Misra limra atiheee akrimee maswaahu 'asaaa any-yanfa'anaaa aw nattakhizahoo waladaa; wa kazaalika mak-kannaa li-Yoosufa fil ardi wa linu'allimahoo min taaweelil ahaadees; wallaahu ghaalibun 'alaaa amrihee wa laakinna aksaran naasi laa ya'lamoon", english: "The man in Egypt who bought him, said to his wife: \"Make his stay (among us) honourable: may be he will bring us much good, or we shall adopt him as a son.\" Thus did We establish Joseph in the land, that We might teach him the interpretation of stories (and events). And Allah hath full power and control over His affairs; but most among mankind know it not", romanUrdu: "Misr (Egypt) ke jis shaks ne usey khareeda usne apni biwi se kaha, “isko acchi tarah rakhna, baeed nahin ke yeh hamare liye mufeed(useful) sabit ho ya hum isey beta bana lein”.Is tarah humne Yusuf ke liye us sar-zameen mein qadam jamane ki surat nikali aur usey maamla fahmi ki taleem dene ka intezam kiya. Allah apna kaam karke rehta hai, magar aksar log jantey nahin hain" },
    { number: 22, arabic: "وَلَمَّا بَلَغَ أَشُدَّهُۥٓ ءَاتَيْنَٰهُ حُكْمًۭا وَعِلْمًۭا ۚ وَكَذَٰلِكَ نَجْزِى ٱلْمُحْسِنِينَ", transliteration: "Walamma balagha ashuddahu ataynahu hukman waAAilman wakathalika najzee almuhsineena", transliterationB: "Wa lammaa balagha ashuddahooo aatainaahu bukmanw wa 'ilmaa; wa kazaa lika najzil muhsineen", english: "When Joseph attained His full manhood, We gave him power and knowledge: thus do We reward those who do right", romanUrdu: "Aur jab woh apni poori jawani ko pahuncha to humne usey quwwat e faisla aur ilam ata kiya, is tarah hum neik logon ko jaza dete hain" },
    { number: 23, arabic: "وَرَٰوَدَتْهُ ٱلَّتِى هُوَ فِى بَيْتِهَا عَن نَّفْسِهِۦ وَغَلَّقَتِ ٱلْأَبْوَٰبَ وَقَالَتْ هَيْتَ لَكَ ۚ قَالَ مَعَاذَ ٱللَّهِ ۖ إِنَّهُۥ رَبِّىٓ أَحْسَنَ مَثْوَاىَ ۖ إِنَّهُۥ لَا يُفْلِحُ ٱلظَّٰلِمُونَ", transliteration: "Warawadathu allatee huwa fee baytiha AAan nafsihi waghallaqati alabwaba waqalat hayta laka qala maAAatha Allahi innahu rabbee ahsana mathwaya innahu la yuflihu alththalimoona", transliterationB: "Wa raawadat hul latee huwa fee baitihaa 'an nafsihee wa ghallaqatil abwaaba wa qaalat haita lak; qaala ma'aazal laahi innahoo rabbeee ahsana maswaay; innahoo laa yuflihuz-zaalimoon", english: "But she in whose house he was, sought to seduce him from his (true) self: she fastened the doors, and said: \"Now come, thou (dear one)!\" He said: \"Allah forbid! truly (thy husband) is my lord! he made my sojourn agreeable! truly to no good come those who do wrong", romanUrdu: "Jis aurat ke ghar mein woh tha woh uspar dorey dalne lagi (began to tempt him) aur ek roz darwaze bandh karke boli “aaja”. Yusuf ne kaha, “khuda ki panaah, mere Rubb ne to mujhey acchi manzilat bakshi (aur main yeh kaam karoon?) Aisey zalim kabhi falaah nahin paya karte”" },
    { number: 24, arabic: "وَلَقَدْ هَمَّتْ بِهِۦ ۖ وَهَمَّ بِهَا لَوْلَآ أَن رَّءَا بُرْهَٰنَ رَبِّهِۦ ۚ كَذَٰلِكَ لِنَصْرِفَ عَنْهُ ٱلسُّوٓءَ وَٱلْفَحْشَآءَ ۚ إِنَّهُۥ مِنْ عِبَادِنَا ٱلْمُخْلَصِينَ", transliteration: "Walaqad hammat bihi wahamma biha lawla an raa burhana rabbihi kathalika linasrifa AAanhu alssooa waalfahshaa innahu min AAibadina almukhlaseena", transliterationB: "Wa laqad hammat bihee wa hamma bihaa law laaa ar ra-aa burhaana rabbih;; kazaalika linasrifa 'anhu sooo'a walfa hshaaa'; innahoo min 'ibaadi nal mukhlaseen", english: "And (with passion) did she desire him, and he would have desired her, but that he saw the evidence of his Lord: thus (did We order) that We might turn away from him (all) evil and shameful deeds: for he was one of Our servants, sincere and purified", romanUrdu: "Woh uski taraf badi aur Yusuf bhi uski taraf badta agar apne Rubb ki burhaan na dekh leta(the proof of his Lord) aisa hua. Taa-ke hum ussey badhi aur behayayi (indecency and immodesty) ko door kardein, dar-haqeeqat woh hamare chuney huey bandonmein se tha" },
    { number: 25, arabic: "وَٱسْتَبَقَا ٱلْبَابَ وَقَدَّتْ قَمِيصَهُۥ مِن دُبُرٍۢ وَأَلْفَيَا سَيِّدَهَا لَدَا ٱلْبَابِ ۚ قَالَتْ مَا جَزَآءُ مَنْ أَرَادَ بِأَهْلِكَ سُوٓءًا إِلَّآ أَن يُسْجَنَ أَوْ عَذَابٌ أَلِيمٌۭ", transliteration: "Waistabaqa albaba waqaddat qameesahu min duburin waalfaya sayyidaha lada albabi qalat ma jazao man arada biahlika sooan illa an yusjana aw AAathabun aleemun", transliterationB: "Wastabaqal baaba wa qaddat qameesahoo min dubu rinw wa alfayaa saiyidahaa ladal baab; qaalat maa jazaaa'u man araada bi ahlika sooo'an illaaa any-yusjana aw azaabun aleem", english: "So they both raced each other to the door, and she tore his shirt from the back: they both found her lord near the door. She said: \"What is the (fitting) punishment for one who formed an evil design against thy wife, but prison or a grievous chastisement", romanUrdu: "Aakhir e kaar Yusuf aur woh aagey peechey darwaze ki taraf bhaage aur usne peechey se Yusuf ka kamees (khinch kar) phadh diya , darwaze par dono ne uske shohar ko maujood paya.Usey dekhte hi aurat kehne lagi, “ kya saza hai us shaks ki jo teri gharwali par niyyat kharab karey? Iske siwa aur kya saza ho sakti hai ke woh qaid kiya jaye ya usey sakht azaab diya jaye”" },
    { number: 26, arabic: "قَالَ هِىَ رَٰوَدَتْنِى عَن نَّفْسِى ۚ وَشَهِدَ شَاهِدٌۭ مِّنْ أَهْلِهَآ إِن كَانَ قَمِيصُهُۥ قُدَّ مِن قُبُلٍۢ فَصَدَقَتْ وَهُوَ مِنَ ٱلْكَٰذِبِينَ", transliteration: "Qala hiya rawadatnee AAan nafsee washahida shahidun min ahliha in kana qameesuhu qudda min qubulin fasadaqat wahuwa mina alkathibeena", transliterationB: "Qaala hiya raawadatnee 'an nafsee wa shahida shaahidum min ahlihaa in kaana qameesuhoo qudda min qubulin fasadaqat wa huwa minal kaazibeen", english: "He said: \"It was she that sought to seduce me - from my (true) self.\" And one of her household saw (this) and bore witness, (thus):- \"If it be that his shirt is rent from the front, then is her tale true, and he is a liar", romanUrdu: "Yusuf ne kaha “yahi mujhey phaansne ki koshish kar rahi thi”. Is aurat ke apne kumbe(family) walon mein se ek shaks ne (qarene ki) shahadat pesh ki ke “agar Yusuf ka kamees aagey se phata ho to aurat sacchi hai aur yeh jhoota" },
    { number: 27, arabic: "وَإِن كَانَ قَمِيصُهُۥ قُدَّ مِن دُبُرٍۢ فَكَذَبَتْ وَهُوَ مِنَ ٱلصَّٰدِقِينَ", transliteration: "Wain kana qameesuhu qudda min duburin fakathabat wahuwa mina alssadiqeena", transliterationB: "Wa in kaana qameesuhoo qudda min duburin fakazabat wa huwa minas saadiqeen", english: "But if it be that his shirt is torn from the back, then is she the liar, and he is telling the truth", romanUrdu: "Aur agar uska kamees peeche se phata ho to aurat jhooti hai aur yeh saccha”" },
    { number: 28, arabic: "فَلَمَّا رَءَا قَمِيصَهُۥ قُدَّ مِن دُبُرٍۢ قَالَ إِنَّهُۥ مِن كَيْدِكُنَّ ۖ إِنَّ كَيْدَكُنَّ عَظِيمٌۭ", transliteration: "Falamma raa qameesahu qudda min duburin qala innahu min kaydikunna inna kaydakunna AAatheemun", transliterationB: "Falammaa ra-aa qamee sahoo qudda min duburin qaala innahoo min kaidikunna inna kaidakunna 'azeem", english: "So when he saw his shirt,- that it was torn at the back,- (her husband) said: \"Behold! It is a snare of you women! truly, mighty is your snare", romanUrdu: "Jab shohar ne dekha ke Yusuf ka kamees peechey se phata hai to usne kaha “yeh tum auraton ki chalakiyan hain, waqayi badey gazab ki hoti hai tumhari chalein" },
    { number: 29, arabic: "يُوسُفُ أَعْرِضْ عَنْ هَٰذَا ۚ وَٱسْتَغْفِرِى لِذَنۢبِكِ ۖ إِنَّكِ كُنتِ مِنَ ٱلْخَاطِـِٔينَ", transliteration: "Yoosufu aAArid AAan hatha waistaghfiree lithanbiki innaki kunti mina alkhatieena", transliterationB: "Yoosofu a'rid 'an haaza wastaghfiree lizambiki innaki kunti minal khaati'een", english: "O Joseph, pass this over! (O wife), ask forgiveness for thy sin, for truly thou hast been at fault", romanUrdu: "Yusuf, is maamle se darguzar kar aur aey aurat, tu apne kasoor ki maafi maang, tu hi asal mein khatakaar thi.”" },
    { number: 30, arabic: "۞ وَقَالَ نِسْوَةٌۭ فِى ٱلْمَدِينَةِ ٱمْرَأَتُ ٱلْعَزِيزِ تُرَٰوِدُ فَتَىٰهَا عَن نَّفْسِهِۦ ۖ قَدْ شَغَفَهَا حُبًّا ۖ إِنَّا لَنَرَىٰهَا فِى ضَلَٰلٍۢ مُّبِينٍۢ", transliteration: "Waqala niswatun fee almadeenati imraatu alAAazeezi turawidu fataha AAan nafsihi qad shaghafaha hubban inna lanaraha fee dalalin mubeenin", transliterationB: "Wa qaala niswatun filma deenatim ra atul'Azeezi turaawidu fataahaa 'an nafsihee qad shaghafahaa bubbaa; innaa lana raahaa fee dalaalim mubeen", english: "Ladies said in the City: \"The wife of the (great) 'Aziz is seeking to seduce her slave from his (true) self: Truly hath he inspired her with violent love: we see she is evidently going astray", romanUrdu: "Shehar ki auratein aapas mein charcha karne lagi ke “azeez ki biwi apne naujawan ghulaam ke peechey padi hui hai, muhabbat ne usko be-qaabu kar rakkha hai. Hamare nazdeek to woh sareeh galati kar rahi hai”" },
    { number: 31, arabic: "فَلَمَّا سَمِعَتْ بِمَكْرِهِنَّ أَرْسَلَتْ إِلَيْهِنَّ وَأَعْتَدَتْ لَهُنَّ مُتَّكَـًۭٔا وَءَاتَتْ كُلَّ وَٰحِدَةٍۢ مِّنْهُنَّ سِكِّينًۭا وَقَالَتِ ٱخْرُجْ عَلَيْهِنَّ ۖ فَلَمَّا رَأَيْنَهُۥٓ أَكْبَرْنَهُۥ وَقَطَّعْنَ أَيْدِيَهُنَّ وَقُلْنَ حَٰشَ لِلَّهِ مَا هَٰذَا بَشَرًا إِنْ هَٰذَآ إِلَّا مَلَكٌۭ كَرِيمٌۭ", transliteration: "Falamma samiAAat bimakrihinna arsalat ilayhinna waaAAtadat lahunna muttakaan waatat kulla wahidatin minhunna sikkeenan waqalati okhruj AAalayhinna falamma raaynahu akbarnahu waqattaAAna aydiyahunna waqulna hasha lillahi ma hatha basharan in hatha illa malakun kareemun", transliterationB: "Falammaa sami'at bimak rihinna arsalat ilaihinna wa a'tadat lahunna muttaka anw wa aatat kulla waahidatim min hunna sikkeenanw wa qaala tikh ruj 'alaihinna falammaa ra aynahooo akbarnahoo wa qatta'na aydiyahunna wa qulna haasha lillaahi maa haaza basharaa; in haazaaa illaa malakun kareem", english: "When she heard of their malicious talk, she sent for them and prepared a banquet for them: she gave each of them a knife: and she said (to Joseph), \"Come out before them.\" When they saw him, they did extol him, and (in their amazement) cut their hands: they said, \"Allah preserve us! no mortal is this! this is none other than a noble angel", romanUrdu: "Usne jo unki yeh makkarana baatein suni to unko bulawa bhej diya aur unke liye takiya-daar majlis aarasta ki aur ziyafat mein har ek ke aagey ek ek churi (knife) rakh di . (Phir ain us waqt jabke woh phal kaat kaat kar kha rahi thi) usne Yusuf ko ishara kiya ke unke saamne nikal aa. Jab un auraton ki nigaah uspar padi to woh dangg reh gayi aur apne haath kaat baithi aur be- saakhta (spontaneously) pukar utthi “ haasha-lil-laah(God protect us), yeh shaks Insaan nahin hai, yeh to koi buzurg farishta hai”" },
    { number: 32, arabic: "قَالَتْ فَذَٰلِكُنَّ ٱلَّذِى لُمْتُنَّنِى فِيهِ ۖ وَلَقَدْ رَٰوَدتُّهُۥ عَن نَّفْسِهِۦ فَٱسْتَعْصَمَ ۖ وَلَئِن لَّمْ يَفْعَلْ مَآ ءَامُرُهُۥ لَيُسْجَنَنَّ وَلَيَكُونًۭا مِّنَ ٱلصَّٰغِرِينَ", transliteration: "Qalat fathalikunna allathee lumtunnanee feehi walaqad rawadtuhu AAan nafsihi faistAAsama walain lam yafAAal ma amuruhu layusjananna walayakoonan mina alssaghireena", transliterationB: "Qaalat fazaalikunnal lazee lumtunnanee feeh; wa laqad raawattuhoo 'an nafsihee fasta'sam; wa la'il lam yaf'al maaa aamuruhoo la yusjananna wa la yakoonam minas saaghireen", english: "She said: \"There before you is the man about whom ye did blame me! I did seek to seduce him from his (true) self but he did firmly save himself guiltless!.... and now, if he doth not my bidding, he shall certainly be cast into prison, and (what is more) be of the company of the vilest", romanUrdu: "Azeez ki biwi ne kaha “dekh liya! Yeh hai woh shaks jiske maamle mein tum mujhpar baatein banati thi. Beshak maine isey rujhane (seduce) ki koshish ki thi magar yeh bach nikla. Agar yeh mera kehna na maanega to qaid kiya jayega aur bahut zaleel o khwar hoga" },
    { number: 33, arabic: "قَالَ رَبِّ ٱلسِّجْنُ أَحَبُّ إِلَىَّ مِمَّا يَدْعُونَنِىٓ إِلَيْهِ ۖ وَإِلَّا تَصْرِفْ عَنِّى كَيْدَهُنَّ أَصْبُ إِلَيْهِنَّ وَأَكُن مِّنَ ٱلْجَٰهِلِينَ", transliteration: "Qala rabbi alssijnu ahabbu ilayya mimma yadAAoonanee ilayhi wailla tasrif AAannee kaydahunna asbu ilayhinna waakun mina aljahileena", transliterationB: "Qaala rabbis sijnu ahabbu ilaiya mimma yad'oo naneee 'ilaihi wa illaa tasrif 'annee kaidahunna asbu ilaihinna wa akum minal jaahileen", english: "He said: \"O my Lord! the prison is more to my liking than that to which they invite me: Unless Thou turn away their snare from me, I should (in my youthful folly) feel inclined towards them and join the ranks of the ignorant", romanUrdu: "Yusuf ne kaha “aey mere Rubb, qaid mujhey manzoor hai ba-nisbat iske ke main woh kaam karoon jo yeh log mujhse chahte hain aur agar tu nay inki chaalon ko mujhse dafa na kiya to main inke daam mein phans jaunga aur jahilon mein shamil ho rahunga" },
    { number: 34, arabic: "فَٱسْتَجَابَ لَهُۥ رَبُّهُۥ فَصَرَفَ عَنْهُ كَيْدَهُنَّ ۚ إِنَّهُۥ هُوَ ٱلسَّمِيعُ ٱلْعَلِيمُ", transliteration: "Faistajaba lahu rabbuhu fasarafa AAanhu kaydahunna innahu huwa alssameeAAu alAAaleemu", transliterationB: "Fastajaaba lahoo rabbuhoo fasarafa 'anhu kaidahunn; innahoo Huswas_Samee'ul 'Aleem", english: "So his Lord hearkened to him (in his prayer), and turned away from him their snare: Verily He heareth and knoweth (all things)", romanUrdu: "Uske Rubb ne uski dua qabool ki aur un auraton ki chalein ussey dafa kardi. Beshak wahi hai jo sab ki sunta aur sab kuch jaanta hai" },
    { number: 35, arabic: "ثُمَّ بَدَا لَهُم مِّنۢ بَعْدِ مَا رَأَوُا۟ ٱلْءَايَٰتِ لَيَسْجُنُنَّهُۥ حَتَّىٰ حِينٍۢ", transliteration: "Thumma bada lahum min baAAdi ma raawoo alayati layasjununnahu hatta heenin", transliterationB: "Summa badaa lahum mim ba'di maa ra-awul Aayaati layasjununnahoo hatta heen", english: "Then it occurred to the men, after they had seen the signs, (that it was best) to imprison him for a time", romanUrdu: "Phir un logon ko yeh soojhi ke ek muddat ke liye usey qaid kardein halanke woh ( uski paak daamani aur khud apni auraton ke burey atwar ki) sareeh nishaniyan dekh chuke thay" },
    { number: 36, arabic: "وَدَخَلَ مَعَهُ ٱلسِّجْنَ فَتَيَانِ ۖ قَالَ أَحَدُهُمَآ إِنِّىٓ أَرَىٰنِىٓ أَعْصِرُ خَمْرًۭا ۖ وَقَالَ ٱلْءَاخَرُ إِنِّىٓ أَرَىٰنِىٓ أَحْمِلُ فَوْقَ رَأْسِى خُبْزًۭا تَأْكُلُ ٱلطَّيْرُ مِنْهُ ۖ نَبِّئْنَا بِتَأْوِيلِهِۦٓ ۖ إِنَّا نَرَىٰكَ مِنَ ٱلْمُحْسِنِينَ", transliteration: "Wadakhala maAAahu alssijna fatayani qala ahaduhuma innee aranee aAAsiru khamran waqala alakharu innee aranee ahmilu fawqa rasee khubzan takulu alttayru minhu nabbina bitaweelihi inna naraka mina almuhsineena", transliterationB: "Wa dakhala ma'ahussijna fata yaan; qaala ahaduhumaaa inneee araaneee a'siru khamranw wa qaalal aakharu inneee khubzan taakulut tairu minh; nabbi 'naa bitaaweelihee innaa naraaka minal muhsineen", english: "Now with him there came into the prison two young men. Said one of them: \"I see myself (in a dream) pressing wine.\" said the other: \"I see myself (in a dream) carrying bread on my head, and birds are eating, thereof.\" \"Tell us\" (they said) \"The truth and meaning thereof: for we see thou art one that doth good (to all)", romanUrdu: "Qaid-khane(prison) mein do ghulaam aur bhi uske saath daakhil huey. Ek roz un mein se ek ne ussey kaha “ maine khwab mein dekha hai ke main sharaab kasheed kar raha hoon” dusre ne kaha, “maine dekha ke mere sar par rotiyan rakkhi hain aur parindey unko kha rahey hain”. Dono ne kaha “humein iski tabeer bataiye, hum dekhte hain ke aap ek neik aadmi hain”" },
    { number: 37, arabic: "قَالَ لَا يَأْتِيكُمَا طَعَامٌۭ تُرْزَقَانِهِۦٓ إِلَّا نَبَّأْتُكُمَا بِتَأْوِيلِهِۦ قَبْلَ أَن يَأْتِيَكُمَا ۚ ذَٰلِكُمَا مِمَّا عَلَّمَنِى رَبِّىٓ ۚ إِنِّى تَرَكْتُ مِلَّةَ قَوْمٍۢ لَّا يُؤْمِنُونَ بِٱللَّهِ وَهُم بِٱلْءَاخِرَةِ هُمْ كَٰفِرُونَ", transliteration: "Qala la yateekuma taAAamun turzaqanihi illa nabbatukuma bitaweelihi qabla an yatiyakuma thalikuma mimma AAallamanee rabbee innee taraktu millata qawmin la yuminoona biAllahi wahum bialakhirati hum kafiroona", transliterationB: "Qaala laa yaateekumaa ta'aamun turzaqaaniheee illaa nabbaatukumaa bitaaweelihee qabla any yaatiyakumaa; zaali kumaa mimmaa 'allamanee rabbee; innee taraktu millata qawmil laa yu'minoona billaahi wahum bil aakhirati hum kaafiroon", english: "He said: \"Before any food comes (in due course) to feed either of you, I will surely reveal to you the truth and meaning of this ere it befall you: that is part of the (duty) which my Lord hath taught me. I have (I assure you) abandoned the ways of a people that believe not in Allah and that (even) deny the Hereafter", romanUrdu: "Yusuf ne kaha: “yahan jo khana tumhein mila karta hai uske aane se pehle main tumhein in khwabon ki tabeer bata dunga. Yeh ilam un uloom se hai jo mere Rubb ne mujhey ata kiye hain. Waqiya yeh hai ke maine un logon ka tareeqa chodh kar jo Allah par iman nahin latey aur aakhirat ka inkar karte hain" },
    { number: 38, arabic: "وَٱتَّبَعْتُ مِلَّةَ ءَابَآءِىٓ إِبْرَٰهِيمَ وَإِسْحَٰقَ وَيَعْقُوبَ ۚ مَا كَانَ لَنَآ أَن نُّشْرِكَ بِٱللَّهِ مِن شَىْءٍۢ ۚ ذَٰلِكَ مِن فَضْلِ ٱللَّهِ عَلَيْنَا وَعَلَى ٱلنَّاسِ وَلَٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَشْكُرُونَ", transliteration: "WaittabaAAtu millata abaee ibraheema waishaqa wayaAAqooba ma kana lana an nushrika biAllahi min shayin thalika min fadli Allahi AAalayna waAAala alnnasi walakinna akthara alnnasi la yashkuroona", transliterationB: "Wattab'tu millata aabaaa'eee Ibraaheema wa Ishaaqa wa Ya'qoob; maa kaana lanaaa an nushrika billaahi min shai' zaalikamin fadlil laahi 'alainaa wa 'alan naasi wa laakinna aksaran naasi laa yashkuroon", english: "And I follow the ways of my fathers,- Abraham, Isaac, and Jacob; and never could we attribute any partners whatever to Allah: that (comes) of the grace of Allah to us and to mankind: yet most men are not grateful", romanUrdu: "Apne buzurgon, Ibrahim, Ishaq aur yaqub ka tareeqa ikhtiyar kiya hai, hamara yeh kaam nahin hai ke Allah ke saath kisi ko shareek tehehrayein .Dar-haqeeqat yeh Allah ka fazal hai humpar aur Insaano par (ke usne apne siwa kisi ka banda humein nahin banaya) magar aksar log shukar nahin karte" },
    { number: 39, arabic: "يَٰصَىٰحِبَىِ ٱلسِّجْنِ ءَأَرْبَابٌۭ مُّتَفَرِّقُونَ خَيْرٌ أَمِ ٱللَّهُ ٱلْوَٰحِدُ ٱلْقَهَّارُ", transliteration: "Ya sahibayi alssijni aarbabun mutafarriqoona khayrun ami Allahu alwahidu alqahharu", transliterationB: "Yaa saahibayis sijni 'a-arbaabum mutafarriqoona khayrun amil laahul waahidul qahhaar", english: "O my two companions of the prison! (I ask you): are many lords differing among themselves better, or the One Allah, Supreme and Irresistible", romanUrdu: "Aey zindan(prison) ke saathiyon (fellow prisoners), tum khud hi socho ke bahut se mutafarriq(various) Rubb behtar hain ya woh ek Allah jo sab par gaalib hai" },
    { number: 40, arabic: "مَا تَعْبُدُونَ مِن دُونِهِۦٓ إِلَّآ أَسْمَآءًۭ سَمَّيْتُمُوهَآ أَنتُمْ وَءَابَآؤُكُم مَّآ أَنزَلَ ٱللَّهُ بِهَا مِن سُلْطَٰنٍ ۚ إِنِ ٱلْحُكْمُ إِلَّا لِلَّهِ ۚ أَمَرَ أَلَّا تَعْبُدُوٓا۟ إِلَّآ إِيَّاهُ ۚ ذَٰلِكَ ٱلدِّينُ ٱلْقَيِّمُ وَلَٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَعْلَمُونَ", transliteration: "Ma taAAbudoona min doonihi illa asmaan sammaytumooha antum waabaokum ma anzala Allahu biha min sultanin ini alhukmu illa lillahi amara alla taAAbudoo illa iyyahu thalika alddeenu alqayyimu walakinna akthara alnnasi la yaAAlamoona", transliterationB: "Maa ta'budoona min doonihee illaaa asmaaa'an sam maitumoohaaa antum wa aabaaa'ukum maaa anzalal laahu bihaa min sultan; inilhukmu illaa lillaah; amara allaa ta'budooo illaaa iyyaah; zaalikad deenul qaiyimu wa laakinna aksaran naasi laa ya'lamoon", english: "If not Him, ye worship nothing but names which ye have named,- ye and your fathers,- for which Allah hath sent down no authority: the command is for none but Allah: He hath commanded that ye worship none but Him: that is the right religion, but most men understand not", romanUrdu: "Usko chodh kar tum jinki bandagi kar rahey ho woh iske siwa kuch nahin hain ke bas chandh naam hain jo tumne aur tumhare aabaa o ajdaad ne rakh liye hain. Allah ne unke liye koi sanad nazil nahin ki. Farma rawayi(Sovereignty) ka iqtedar Allah ke siwa kisi ke liye nahin hai. Uska hukum hai ke khud uske siwa tum kisi ki bandagi na karo, yahi theith seedha tareeq e zindagi hai, magar aksar log jaante nahin hain" },
    { number: 41, arabic: "يَٰصَىٰحِبَىِ ٱلسِّجْنِ أَمَّآ أَحَدُكُمَا فَيَسْقِى رَبَّهُۥ خَمْرًۭا ۖ وَأَمَّا ٱلْءَاخَرُ فَيُصْلَبُ فَتَأْكُلُ ٱلطَّيْرُ مِن رَّأْسِهِۦ ۚ قُضِىَ ٱلْأَمْرُ ٱلَّذِى فِيهِ تَسْتَفْتِيَانِ", transliteration: "Ya sahibayi alssijni amma ahadukuma fayasqee rabbahu khamran waamma alakharu fayuslabu fatakulu alttayru min rasihi qudiya alamru allathee feehi tastaftiyani", transliterationB: "Yaa saahibayis sijni ammaaa ahadukumaa fa yasqee rabbahoo khamranw wa ammal aakharu fa yuslabu fataakulut tairu mir raasih; qudiyal amrul lazee feehi tastaftiyaan", english: "O my two companions of the prison! As to one of you, he will pour out the wine for his lord to drink: as for the other, he will hang from the cross, and the birds will eat from off his head. (so) hath been decreed that matter whereof ye twain do enquire", romanUrdu: "Aey zindan ke saathiyon , tumhare khwab ki tabeer yeh hai ke tum mein se ek to apne Rubb (shah e Misr) ko sharaab pilayega, raha dusra to usey suli par chadhaya jayega (crucified) aur parindey uska sar noch noch kar khayenge. Faisla ho gaya us baat ka jo tum puch rahey thay”" },
    { number: 42, arabic: "وَقَالَ لِلَّذِى ظَنَّ أَنَّهُۥ نَاجٍۢ مِّنْهُمَا ٱذْكُرْنِى عِندَ رَبِّكَ فَأَنسَىٰهُ ٱلشَّيْطَٰنُ ذِكْرَ رَبِّهِۦ فَلَبِثَ فِى ٱلسِّجْنِ بِضْعَ سِنِينَ", transliteration: "Waqala lillathee thanna annahu najin minhuma othkurnee AAinda rabbika faansahu alshshaytanu thikra rabbihi falabitha fee alssijni bidAAa sineena", transliterationB: "Wa qaala lillazee zanna annahoo najim minhumaz kurnee 'inda rabbika fa-ansaahush Shaitaanu zikra Rabbihee falabisa fis sijni bad'a sineen", english: "And of the two, to that one whom he consider about to be saved, he said: \"Mention me to thy lord.\" But Satan made him forget to mention him to his lord: and (Joseph) lingered in prison a few (more) years", romanUrdu: "Phir un mein se jiske mutaaliq khayal tha ke woh riha(release) ho jayega ussey Yusuf ne kaha ke “apne Rubb (shah-e-Misr) se mera zikr karna”. Magar shaytan ne usey aisa gaflat mein daala ke woh apne Rubb (Shah-e-Misr) se uska zikr karna bhool gaya aur Yusuf kai saal qaid-khane mein pada raha" },
    { number: 43, arabic: "وَقَالَ ٱلْمَلِكُ إِنِّىٓ أَرَىٰ سَبْعَ بَقَرَٰتٍۢ سِمَانٍۢ يَأْكُلُهُنَّ سَبْعٌ عِجَافٌۭ وَسَبْعَ سُنۢبُلَٰتٍ خُضْرٍۢ وَأُخَرَ يَابِسَٰتٍۢ ۖ يَٰٓأَيُّهَا ٱلْمَلَأُ أَفْتُونِى فِى رُءْيَٰىَ إِن كُنتُمْ لِلرُّءْيَا تَعْبُرُونَ", transliteration: "Waqala almaliku innee ara sabAAa baqaratin simanin yakuluhunna sabAAun AAijafun wasabAAa sunbulatin khudrin waokhara yabisatin ya ayyuha almalao aftoonee fee ruyaya in kuntum lilrruya taAAburoona", transliterationB: "Wa qaalal maliku inneee araa sab'a baqaraatin simaaniny yaakuluhunna sab'un 'ijaafunw wa sab'a sumbulaatinkhudrinw wa ukhara yaabisaat; yaaa ayuhal mala-u aftoonee fee nu'yaaya in kuntum lirru'yaa ta'buroon", english: "The king (of Egypt) said: \"I do see (in a vision) seven fat kine, whom seven lean ones devour, and seven green ears of corn, and seven (others) withered. O ye chiefs! Expound to me my vision if it be that ye can interpret visions", romanUrdu: "Ek roz baadshah ne kaha “ maine khwab mein dekha hai ke saat (seven) moti gaayein (cows) jinko saat (seven) dubli (lean) gaayein kha rahi hain, aur anaaj ke saat baalein hari (green) hain aur dursi saat sukhi. Aey ehle darbar , mujhey is khwab ki tabeer batao agar tum khwabon ka matlab samajhte ho.”" },
    { number: 44, arabic: "قَالُوٓا۟ أَضْغَٰثُ أَحْلَٰمٍۢ ۖ وَمَا نَحْنُ بِتَأْوِيلِ ٱلْأَحْلَٰمِ بِعَٰلِمِينَ", transliteration: "Qaloo adghathu ahlamin wama nahnu bitaweeli alahlami biAAalimeena", transliterationB: "Qaalooo adghaasu ahlaa minw wa maa nahnu bitaaweelil ahlaami bi'aalimeen", english: "They said: \"A confused medley of dreams: and we are not skilled in the interpretation of dreams", romanUrdu: "Logon ne kaha “yeh to pareshan khwabon ki baatein hain aur hum is tarah ke khwabon ka matlab nahin jantey”" },
    { number: 45, arabic: "وَقَالَ ٱلَّذِى نَجَا مِنْهُمَا وَٱدَّكَرَ بَعْدَ أُمَّةٍ أَنَا۠ أُنَبِّئُكُم بِتَأْوِيلِهِۦ فَأَرْسِلُونِ", transliteration: "Waqala allathee naja minhuma waiddakara baAAda ommatin ana onabbiokum bitaweelihi faarsilooni", transliterationB: "Wa qaalal lazee najaa minhumaa waddakara ba'da ummatin ana unabbi'ukum bitalweelihee fa-arsiloon", english: "But the man who had been released, one of the two (who had been in prison) and who now bethought him after (so long) a space of time, said: \"I will tell you the truth of its interpretation: send ye me (therefore)", romanUrdu: "Un do qaidiyon mein se jo shaks bach gaya tha aur usey ek muddat daraaz ke baad ab baat yaad aayi, usne kaha “main aap hazraat ko iski taaweel batata hoon, mujhey zara (qaid-khane mein Yusuf ke paas) bhej dijiye”" },
    { number: 46, arabic: "يُوسُفُ أَيُّهَا ٱلصِّدِّيقُ أَفْتِنَا فِى سَبْعِ بَقَرَٰتٍۢ سِمَانٍۢ يَأْكُلُهُنَّ سَبْعٌ عِجَافٌۭ وَسَبْعِ سُنۢبُلَٰتٍ خُضْرٍۢ وَأُخَرَ يَابِسَٰتٍۢ لَّعَلِّىٓ أَرْجِعُ إِلَى ٱلنَّاسِ لَعَلَّهُمْ يَعْلَمُونَ", transliteration: "Yoosufu ayyuha alssiddeequ aftina fee sabAAi baqaratin simanin yakuluhunna sabAAun AAijafun wasabAAi sunbulatin khudrin waokhara yabisatin laAAallee arjiAAu ila alnnasi laAAallahum yaAAlamoona", transliterationB: "Yoosufu ayyuhas siddee qu aftinaa fee sab'i baqaraatin simaaniny yaakuluhunna sab'un 'ijaafunw wa sabi'i sumbulaatin khudrinw wa ukhara yaabisaatil la'alleee arj'u ilan naasi la'allahum ya'lamoon", english: "O Joseph!\" (he said) \"O man of truth! Expound to us (the dream) of seven fat kine whom seven lean ones devour, and of seven green ears of corn and (seven) others withered: that I may return to the people, and that they may understand", romanUrdu: "Usne jaa kar kaha “Yusuf, aey sarapa raasti(O man of righteousness), mujhe is khwab ka matlab bata ke saat moti gaayein jinko saat dubli gaayein kha rahi hain aur saat baalein hari (green ears of corn ) hain aur saat sukhi , shayad ke main un logon ke paas jaaun aur shayad ke woh jaan lein”" },
    { number: 47, arabic: "قَالَ تَزْرَعُونَ سَبْعَ سِنِينَ دَأَبًۭا فَمَا حَصَدتُّمْ فَذَرُوهُ فِى سُنۢبُلِهِۦٓ إِلَّا قَلِيلًۭا مِّمَّا تَأْكُلُونَ", transliteration: "Qala tazraAAoona sabAAa sineena daaban fama hasadtum fatharoohu fee sunbulihi illa qaleelan mimma takuloona", transliterationB: "Qaala tazra'oona sab'a sineena da aban famaa basattum fazaroohu fee sumbu liheee illaa qaleelam mimmaa taakuloon", english: "(Joseph) said: \"For seven years shall ye diligently sow as is your wont: and the harvests that ye reap, ye shall leave them in the ear,- except a little, of which ye shall eat", romanUrdu: "Yusuf ne kaha “saat baras tak lagataar tumlog kheti-baadi karte rahoge. Is dauraan mein jo fasalein (crops) tum kaato un mein se bas thoda sa hisaa, jo tumhari khuraak ke kaam aaye nikalo aur baaqi ko uski baalon hi mein rehne do" },
    { number: 48, arabic: "ثُمَّ يَأْتِى مِنۢ بَعْدِ ذَٰلِكَ سَبْعٌۭ شِدَادٌۭ يَأْكُلْنَ مَا قَدَّمْتُمْ لَهُنَّ إِلَّا قَلِيلًۭا مِّمَّا تُحْصِنُونَ", transliteration: "Thumma yatee min baAAdi thalika sabAAun shidadun yakulna ma qaddamtum lahunna illa qaleelan mimma tuhsinoona", transliterationB: "Summa yaatee mim ba'di zaalika sab'un shidaaduny yaa kulna maa qaddamtum lahunna illaa qaleelam mimma tuhsinoon", english: "Then will come after that (period) seven dreadful (years), which will devour what ye shall have laid by in advance for them,- (all) except a little which ye shall have (specially) guarded", romanUrdu: "Phir saat baras bahut sakht aayenge. Us zamane mein woh sab galla(corn) kha liya jayega jo tum us waqt ke liye jama karoge, agar kuch bachega to bas wahi jo tumne mehfooz kar rakkha ho" },
    { number: 49, arabic: "ثُمَّ يَأْتِى مِنۢ بَعْدِ ذَٰلِكَ عَامٌۭ فِيهِ يُغَاثُ ٱلنَّاسُ وَفِيهِ يَعْصِرُونَ", transliteration: "Thumma yatee min baAAdi thalika AAamun feehi yughathu alnnasu wafeehi yaAAsiroona", transliterationB: "Summa yadtee mim ba'di zaalika 'aamun feehi yughaa sun naasu wa feehi ya'siroon", english: "Then will come after that (period) a year in which the people will have abundant water, and in which they will press (wine and oil)", romanUrdu: "Iske baad phir ek saal aisa aayega jis mein baraan-e-rehmat (abundant rainfall) se logon ki fariyad rasi ki jayegi aur woh ras nichodenge (juice and oil)”" },
    { number: 50, arabic: "وَقَالَ ٱلْمَلِكُ ٱئْتُونِى بِهِۦ ۖ فَلَمَّا جَآءَهُ ٱلرَّسُولُ قَالَ ٱرْجِعْ إِلَىٰ رَبِّكَ فَسْـَٔلْهُ مَا بَالُ ٱلنِّسْوَةِ ٱلَّٰتِى قَطَّعْنَ أَيْدِيَهُنَّ ۚ إِنَّ رَبِّى بِكَيْدِهِنَّ عَلِيمٌۭ", transliteration: "Waqala almaliku itoonee bihi falamma jaahu alrrasoolu qala irjiAA ila rabbika faisalhu ma balu alnniswati allatee qattaAAna aydiyahunna inna rabbee bikaydihinna AAaleemun", transliterationB: "Wa qaalal maliku'toonee bihee falammaa jaaa'ahur rasoolu qaalar-ji ilaa rabbika fas'alhu maa baalun niswatil laatee qatta'na aydiyahunn; inna Rabbee bikaidihinna 'Aleem", english: "So the king said: \"Bring ye him unto me.\" But when the messenger came to him, (Joseph) said: \"Go thou back to thy lord, and ask him, 'What is the state of mind of the ladies who cut their hands'? For my Lord is certainly well aware of their snare", romanUrdu: "Baadshah ne kaha usey mere paas lao. Magar jab shahi faristaada (royal envoy) Yusuf ke paas pahuncha to usne kaha “apne Rubb ke paas wapas ja aur ussey puch ke un auraton ka kya maamla hai jinhon ne apne haath kat liye thay? Mera Rubb to unki makkari se waqif hi hai.”" },
    { number: 51, arabic: "قَالَ مَا خَطْبُكُنَّ إِذْ رَٰوَدتُّنَّ يُوسُفَ عَن نَّفْسِهِۦ ۚ قُلْنَ حَٰشَ لِلَّهِ مَا عَلِمْنَا عَلَيْهِ مِن سُوٓءٍۢ ۚ قَالَتِ ٱمْرَأَتُ ٱلْعَزِيزِ ٱلْـَٰٔنَ حَصْحَصَ ٱلْحَقُّ أَنَا۠ رَٰوَدتُّهُۥ عَن نَّفْسِهِۦ وَإِنَّهُۥ لَمِنَ ٱلصَّٰدِقِينَ", transliteration: "Qala ma khatbukunna ith rawadtunna yoosufa AAan nafsihi qulna hasha lillahi ma AAalimna AAalayhi min sooin qalati imraatu alAAazeezi alana hashasa alhaqqu ana rawadtuhu AAan nafsihi wainnahu lamina alssadiqeena", transliterationB: "Qaala maa khatbukunna iz raawattunna Yoosufa 'annafsih; qulna haasha lillaahi maa 'alimnaa 'alaihi min sooo'; qaalatim ra atul 'Azeezil 'aana hashasal haqq, ana raawat tuhoo 'an nafsihee wa innahoo laminas saadiqeen", english: "(The king) said (to the ladies): \"What was your affair when ye did seek to seduce Joseph from his (true) self?\" The ladies said: \"Allah preserve us! no evil know we against him!\" Said the 'Aziz's wife: \"Now is the truth manifest (to all): it was I who sought to seduce him from his (true) self: He is indeed of those who are (ever) true (and virtuous)", romanUrdu: "Is par baadshah ne un auraton se dariyaft kiya “tumhara kya tajurba hai us waqt ka jab tumne Yusuf ko rujhane(entice) ki koshish ki thi?” Sab ne ek zubaan hokar kaha “haasha lillah! (God protect us), humne to usmein badhi(evil) ka shaiba tak na paya.” Azeez ki biwi bol uthi, “ab haqq khul chuka hai, woh main hi thi jisne usko phuslane ki koshish ki thi. beshak woh bilkul saccha hai”" },
    { number: 52, arabic: "ذَٰلِكَ لِيَعْلَمَ أَنِّى لَمْ أَخُنْهُ بِٱلْغَيْبِ وَأَنَّ ٱللَّهَ لَا يَهْدِى كَيْدَ ٱلْخَآئِنِينَ", transliteration: "Thalika liyaAAlama annee lam akhunhu bialghaybi waanna Allaha la yahdee kayda alkhaineena", transliterationB: "Zaalika liya'lama annee lam akhunhu bilghaibi wa annal laaha laa yahdee kaidal khaaa'ineen", english: "This (say I), in order that He may know that I have never been false to him in his absence, and that Allah will never guide the snare of the false ones", romanUrdu: "(Yusuf ne kaha) “Issey meri garz yeh thi ke (azeez) yeh jaan le ke maine dar-purda uski khayanat nahin ki thi, aur yeh ke jo khyanat karte hain unki chaalon ko Allah kamiyabi ki raah par nahin lagata" },
    { number: 53, arabic: "۞ وَمَآ أُبَرِّئُ نَفْسِىٓ ۚ إِنَّ ٱلنَّفْسَ لَأَمَّارَةٌۢ بِٱلسُّوٓءِ إِلَّا مَا رَحِمَ رَبِّىٓ ۚ إِنَّ رَبِّى غَفُورٌۭ رَّحِيمٌۭ", transliteration: "Wama obarrio nafsee inna alnnafsa laammaratun bialssooi illa ma rahima rabbee inna rabbee ghafoorun raheemun", transliterationB: "Wa maa ubarri'u nafsee; innan nafsa la ammaaratum bissooo'i illaa maa rahima Rabbee; inna Rabbee Ghafoorur Raheem", english: "Nor do I absolve my own self (of blame): the (human) soul is certainly prone to evil, unless my Lord do bestow His Mercy: but surely my Lord is Oft-forgiving, Most Merciful", romanUrdu: "Main kuch apne nafs ki baraat nahin kar raha hoon (not holding my soul to be immune from sin), nafs to badhi (burayi) par uksata hi hai , illa yeh ke kisi par mere Rubb ki rehmat ho, beshak mera Rubb bada gafoor o Raheem hai”" },
    { number: 54, arabic: "وَقَالَ ٱلْمَلِكُ ٱئْتُونِى بِهِۦٓ أَسْتَخْلِصْهُ لِنَفْسِى ۖ فَلَمَّا كَلَّمَهُۥ قَالَ إِنَّكَ ٱلْيَوْمَ لَدَيْنَا مَكِينٌ أَمِينٌۭ", transliteration: "Waqala almaliku itoonee bihi astakhlishu linafsee falamma kallamahu qala innaka alyawma ladayna makeenun ameenun", transliterationB: "Wa qaalal maliku' toonee biheee astakhlishu linafsee falammaa kallamahoo qaala innakal yawma ladainaa makeenun ameen", english: "So the king said: \"Bring him unto me; I will take him specially to serve about my own person.\" Therefore when he had spoken to him, he said: \"Be assured this day, thou art, before our own presence, with rank firmly established, and fidelity fully proved", romanUrdu: "Baadshah ne kaha “unhein mere paas lao taa-ke main unko apne liye makhsoos kar loon”. Jab Yusuf ne ussey guftagu ki to usne kaha “ab aap hamare haan qadr o manzilat rakhte hain aur aap ki amanat par pura bharosa hai”" },
    { number: 55, arabic: "قَالَ ٱجْعَلْنِى عَلَىٰ خَزَآئِنِ ٱلْأَرْضِ ۖ إِنِّى حَفِيظٌ عَلِيمٌۭ", transliteration: "Qala ijAAalnee AAala khazaini alardi innee hafeethun AAaleemun", transliterationB: "Qaalaj 'alnee 'alaa khazaaa'inil ardi innee hafeezun 'aleem", english: "(Joseph) said: \"Set me over the store-houses of the land: I will indeed guard them, as one that knows (their importance)", romanUrdu: "Yusuf ne kaha, “mulk ke khazane mere supurd kijiye , main hifazat karne wala bhi hoon aur ilam bhi rakhta hoon”" },
    { number: 56, arabic: "وَكَذَٰلِكَ مَكَّنَّا لِيُوسُفَ فِى ٱلْأَرْضِ يَتَبَوَّأُ مِنْهَا حَيْثُ يَشَآءُ ۚ نُصِيبُ بِرَحْمَتِنَا مَن نَّشَآءُ ۖ وَلَا نُضِيعُ أَجْرَ ٱلْمُحْسِنِينَ", transliteration: "Wakathalika makanna liyoosufa fee alardi yatabawwao minha haythu yashao nuseebu birahmatina man nashao wala nudeeAAu ajra almuhsineena", transliterationB: "Wa kazaalika makkannaa li Yoosufa fil ardi yatabawwa'u minhaa haisu yashaaaa'; nuseebu birahmatinaa man nashaaa'u wa laa nudee'u ajral muhsineen", english: "Thus did We give established power to Joseph in the land, to take possession therein as, when, or where he pleased. We bestow of our Mercy on whom We please, and We suffer not, to be lost, the reward of those who do good", romanUrdu: "Is tarah humne us sar-zameen mein Yusuf ke liye iqteqar (power) ki raah humwaar ki. Woh mukhtar tha ke usmein jahan chahe apni jagah banaye. Hum apni rehmat se jisko chahte hain nawazte hain. Neik logon ka ajar hamare haan maara nahin jata" },
    { number: 57, arabic: "وَلَأَجْرُ ٱلْءَاخِرَةِ خَيْرٌۭ لِّلَّذِينَ ءَامَنُوا۟ وَكَانُوا۟ يَتَّقُونَ", transliteration: "Walaajru alakhirati khayrun lillatheena amanoo wakanoo yattaqoona", transliterationB: "Wa la ajrul Aakhirati khairul lillazeena aamanoo wa kaanoo yattaqoon", english: "But verily the reward of the Hereafter is the best, for those who believe, and are constant in righteousness", romanUrdu: "Aur aakhirat ka ajar un logon ke liye zyada behtar hai jo iman le aaye aur khuda-tarsi ke saath kaam karte rahey" },
    { number: 58, arabic: "وَجَآءَ إِخْوَةُ يُوسُفَ فَدَخَلُوا۟ عَلَيْهِ فَعَرَفَهُمْ وَهُمْ لَهُۥ مُنكِرُونَ", transliteration: "Wajaa ikhwatu yoosufa fadakhaloo AAalayhi faAAarafahum wahum lahu munkiroona", transliterationB: "Wa jaaa'a ikhwatu Yoosufa fadakhaloo 'alaihi fa'arafahum wa hum lahoo munkiroon", english: "Then came Joseph's brethren: they entered his presence, and he knew them, but they knew him not", romanUrdu: "Yusuf ke bhai Misr(egypt) aaye aur uske haan hazir huye, usne unhein pehchan liya magar woh ussey na-aashna thay" },
    { number: 59, arabic: "وَلَمَّا جَهَّزَهُم بِجَهَازِهِمْ قَالَ ٱئْتُونِى بِأَخٍۢ لَّكُم مِّنْ أَبِيكُمْ ۚ أَلَا تَرَوْنَ أَنِّىٓ أُوفِى ٱلْكَيْلَ وَأَنَا۠ خَيْرُ ٱلْمُنزِلِينَ", transliteration: "Walamma jahhazahum bijahazihim qala itoonee biakhin lakum min abeekum ala tarawna annee oofee alkayla waana khayru almunzileena", transliterationB: "Wa lammaa jahhazahum bijahaazihim qaala' toonee bi akhil lakum min abeekum; alaa tarawna anneee oofil kaila wa ana khairul munzileen", english: "And when he had furnished them forth with provisions (suitable) for them, he said: \"Bring unto me a brother ye have, of the same father as yourselves, (but a different mother): see ye not that I pay out full measure, and that I do provide the best hospitality", romanUrdu: "Phir jab usne unka samaan tayyar karwa diya to chalte waqt unse kaha, “apne sautelay bhai ko mere paas lana, dekte nahin ho ke main kis tarah paimana bhar kar deta hoon aur kaisa accha mehmaan nawaz hoon" },
    { number: 60, arabic: "فَإِن لَّمْ تَأْتُونِى بِهِۦ فَلَا كَيْلَ لَكُمْ عِندِى وَلَا تَقْرَبُونِ", transliteration: "Fain lam tatoonee bihi fala kayla lakum AAindee wala taqrabooni", transliterationB: "Fa il lam taatoonee bihee falaa kaila lakum 'indee wa laa taqraboon", english: "Now if ye bring him not to me, ye shall have no measure (of corn) from me, nor shall ye (even) come near me", romanUrdu: "Agar tum usey na laaogey to mere paas tumhare liye koi galla (grain) nahin hai balke tum mere qareeb bhi na phatakna”" },
    { number: 61, arabic: "قَالُوا۟ سَنُرَٰوِدُ عَنْهُ أَبَاهُ وَإِنَّا لَفَٰعِلُونَ", transliteration: "Qaloo sanurawidu AAanhu abahu wainna lafaAAiloona", transliterationB: "Qaaloo sanuraawidu 'anhu abaahu wa innaa lafaa'iloon", english: "They said: \"We shall certainly seek to get our wish about him from his father: Indeed we shall do it", romanUrdu: "Unhon ne kaha, “hum koshish karenge ke walid sahab usey bhejne par razi ho jayein, aur hum aisa zaroor karenge”" },
    { number: 62, arabic: "وَقَالَ لِفِتْيَٰنِهِ ٱجْعَلُوا۟ بِضَٰعَتَهُمْ فِى رِحَالِهِمْ لَعَلَّهُمْ يَعْرِفُونَهَآ إِذَا ٱنقَلَبُوٓا۟ إِلَىٰٓ أَهْلِهِمْ لَعَلَّهُمْ يَرْجِعُونَ", transliteration: "Waqala lifityanihi ijAAaloo bidaAAatahum fee rihalihim laAAallahum yaAArifoonaha itha inqalaboo ila ahlihim laAAallahum yarjiAAoona", transliterationB: "Wa qaala lifityaanihij 'aloo bidaa'atahum fee rihaalihim la'allahum ya'rifoonahaaa izan qalabooo ilaaa ahlihim la'allahum yarji'oon", english: "And (Joseph) told his servants to put their stock-in-trade (with which they had bartered) into their saddle-bags, so they should know it only when they returned to their people, in order that they might come back", romanUrdu: "Yusuf ne apne ghulaamo ko ishara kiya ke “in logon ne galle ke evaz jo maal diya hai woh chupke se unke samaan hi mein rakhdo”. Yeh Yusuf ne is ummed par kiya ke ghar pahunch kar woh apna wapas paya hua maal pehchan jayenge (ya is fayyazi par ehsan-mand hongey) aur ajab nahin ke phir paltein" },
    { number: 63, arabic: "فَلَمَّا رَجَعُوٓا۟ إِلَىٰٓ أَبِيهِمْ قَالُوا۟ يَٰٓأَبَانَا مُنِعَ مِنَّا ٱلْكَيْلُ فَأَرْسِلْ مَعَنَآ أَخَانَا نَكْتَلْ وَإِنَّا لَهُۥ لَحَٰفِظُونَ", transliteration: "Falamma rajaAAoo ila abeehim qaloo ya abana muniAAa minna alkaylu faarsil maAAana akhana naktal wainna lahu lahafithoona", transliterationB: "Falammaa raja'ooo ilaaa abeehim qaaloo yaaa abaanaa muni'a minnal kailu fa arsil ma'anaaa akhaanaa naktal wa innaa lahoo lahaafizoon", english: "Now when they returned to their father, they said: \"O our father! No more measure of grain shall we get (unless we take our brother): So send our brother with us, that we may get our measure; and we will indeed take every care of him", romanUrdu: "Jab woh apne baap ke paas gaye to kaha “abbajaan, aainda humko galla dene se inkar kardiya gaya hai, lihaza aap hamare bhai ko hamare saath bhej dijiye taa-ke hum galla lekar aayein aur uski hifazat ke hum zimmedaar hain”" },
    { number: 64, arabic: "قَالَ هَلْ ءَامَنُكُمْ عَلَيْهِ إِلَّا كَمَآ أَمِنتُكُمْ عَلَىٰٓ أَخِيهِ مِن قَبْلُ ۖ فَٱللَّهُ خَيْرٌ حَٰفِظًۭا ۖ وَهُوَ أَرْحَمُ ٱلرَّٰحِمِينَ", transliteration: "Qala hal amanukum AAalayhi illa kama amintukum AAala akheehi min qablu faAllahu khayrun hafithan wahuwa arhamu alrrahimeena", transliterationB: "Qaala hal aamanukum 'alihi illaa kamaa amintukum 'alaaa akheehimin qabl; fal laahu khairun haafizanw wa Huwa arhamur Raahimeen", english: "He said: \"Shall I trust you with him with any result other than when I trusted you with his brother aforetime? But Allah is the best to take care (of him), and He is the Most Merciful of those who show mercy", romanUrdu: "Baap ne jawab diya “kya main uske maamle mein tumpar waisa hi bharosa karoon jaisa issey phele uske bhai ke maamle mein kar chuka hoon? Allah hi behtar muhafiz (Guardian) hai aur woh sabse badhkar reham farmane wala hai”" },
    { number: 65, arabic: "وَلَمَّا فَتَحُوا۟ مَتَٰعَهُمْ وَجَدُوا۟ بِضَٰعَتَهُمْ رُدَّتْ إِلَيْهِمْ ۖ قَالُوا۟ يَٰٓأَبَانَا مَا نَبْغِى ۖ هَٰذِهِۦ بِضَٰعَتُنَا رُدَّتْ إِلَيْنَا ۖ وَنَمِيرُ أَهْلَنَا وَنَحْفَظُ أَخَانَا وَنَزْدَادُ كَيْلَ بَعِيرٍۢ ۖ ذَٰلِكَ كَيْلٌۭ يَسِيرٌۭ", transliteration: "Walamma fatahoo mataAAahum wajadoo bidaAAatahum ruddat ilayhim qaloo ya abana ma nabghee hathihi bidaAAatuna ruddat ilayna wanameeru ahlana wanahfathu akhana wanazdadu kayla baAAeerin thalika kaylun yaseerun", transliterationB: "Wa lammaa fatahoo mataa 'ahum wajadoo bidaa'atahum ruddat ilaihim qaaloo yaaa abaanaa maa nabghee; haazihee bida 'atunaa ruddat ilainaa wa nameeru ahlanaa wa nahfazu akhaanaa wa nazdaadu kaila ba'eer; zaalika kailuny yaseer", english: "Then when they opened their baggage, they found their stock-in-trade had been returned to them. They said: \"O our father! What (more) can we desire? this our stock-in-trade has been returned to us: so we shall get (more) food for our family; We shall take care of our brother; and add (at the same time) a full camel's load (of grain to our provisions). This is but a small quantity", romanUrdu: "Phir jab unhon ne apna samaan khola to dekha ke unka maal bhi unhein wapas kardiya gaya hai. Yeh dekh kar woh pukar utthey “abbajaan, aur humein kya chahiye, dekhiye yeh hamara maal bhi humein wapas de diya gaya hai. Bas ab hum jayenge aur apne ehal o ayal ke liye rasad (provisions of food) le ayenge , apne bhai ki hifazat bhi karenge aur ek barishtar (an extra camel load of corn) aur zyada bhi le ayenge. Inte galley ka izafa aasani ke saath ho jayega”" },
    { number: 66, arabic: "قَالَ لَنْ أُرْسِلَهُۥ مَعَكُمْ حَتَّىٰ تُؤْتُونِ مَوْثِقًۭا مِّنَ ٱللَّهِ لَتَأْتُنَّنِى بِهِۦٓ إِلَّآ أَن يُحَاطَ بِكُمْ ۖ فَلَمَّآ ءَاتَوْهُ مَوْثِقَهُمْ قَالَ ٱللَّهُ عَلَىٰ مَا نَقُولُ وَكِيلٌۭ", transliteration: "Qala lan orsilahu maAAakum hatta tutooni mawthiqan mina Allahi latatunnanee bihi illa an yuhata bikum falamma atawhu mawthiqahum qala Allahu AAala ma naqoolu wakeelun", transliterationB: "Qaala lan ursilahoo ma'akum hattaa tu'tooni mawsiqam minal laahis lataa tunnanee biheee illaaa nay yuhaata bikum falammaaa aatawhu mawsiqahum qaalal laahu 'alaa maa naqoolu Wakeel", english: "(Jacob) said: \"Never will I send him with you until ye swear a solemn oath to me, in Allah's name, that ye will be sure to bring him back to me unless ye are yourselves hemmed in (and made powerless). And when they had sworn their solemn oath, he said: \"Over all that we say, be Allah the witness and guardian", romanUrdu: "Unke baap ne kaha “main isko hargiz tumhare saath na bhejunga jab tak ke tum Allah ke naam se mujhko paimaan (pledge) na de do ke isey mere paas zaroor wapas lekar aaogey, illa yeh ke kahin tum gher hi liye jao”. Jab unhon ne usko apne apne paiman de diye to usne kaha “dekho, hamare is qaul par Allah nigehbaan hai”" },
    { number: 67, arabic: "وَقَالَ يَٰبَنِىَّ لَا تَدْخُلُوا۟ مِنۢ بَابٍۢ وَٰحِدٍۢ وَٱدْخُلُوا۟ مِنْ أَبْوَٰبٍۢ مُّتَفَرِّقَةٍۢ ۖ وَمَآ أُغْنِى عَنكُم مِّنَ ٱللَّهِ مِن شَىْءٍ ۖ إِنِ ٱلْحُكْمُ إِلَّا لِلَّهِ ۖ عَلَيْهِ تَوَكَّلْتُ ۖ وَعَلَيْهِ فَلْيَتَوَكَّلِ ٱلْمُتَوَكِّلُونَ", transliteration: "Waqala ya baniyya la tadkhuloo min babin wahidin waodkhuloo min abwabin mutafarriqatin wama oghnee AAankum mina Allahi min shayin ini alhukmu illa lillahi AAalayhi tawakkaltu waAAalayhi falyatawakkali almutawakkiloona", transliterationB: "Wa qaala yaa baniyya laa tadkhuloo mim baabinw waa hidinw wadkhuloo min abwaabim mutafarriqah; wa maaa ughnee 'ankum minal laahi min shai'in; inil hukmu illaa lillaahi 'alaihi tawakkaltu wa 'alaihi fal yatawakkalil Mutawakkiloon", english: "Further he said: \"O my sons! enter not all by one gate: enter ye by different gates. Not that I can profit you aught against Allah (with my advice): None can command except Allah: On Him do I put my trust: and let all that trust put their trust on Him", romanUrdu: "Phir usne kaha “ mere bacchon, Misr ke dar-ul-sultanat mein ek darwaze se dakhil na hona balke mukhtalif darwazon se jana. Magar main Allah ki mashiyat se tumko nahin bacha sakta, hukum uske siwa kisi ka bhi nahin chalta. Usi par maine bharosa kiya, aur jisko bhi bharosa karna ho usi par karey”" },
    { number: 68, arabic: "وَلَمَّا دَخَلُوا۟ مِنْ حَيْثُ أَمَرَهُمْ أَبُوهُم مَّا كَانَ يُغْنِى عَنْهُم مِّنَ ٱللَّهِ مِن شَىْءٍ إِلَّا حَاجَةًۭ فِى نَفْسِ يَعْقُوبَ قَضَىٰهَا ۚ وَإِنَّهُۥ لَذُو عِلْمٍۢ لِّمَا عَلَّمْنَٰهُ وَلَٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَعْلَمُونَ", transliteration: "Walamma dakhaloo min haythu amarahum aboohum ma kana yughnee AAanhum mina Allahi min shayin illa hajatan fee nafsi yaAAqooba qadaha wainnahu lathoo AAilmin lima AAallamnahu walakinna akthara alnnasi la yaAAlamoona", transliterationB: "Wa lammaa dakhaloo min haisu amarahum aboohum maa kaana yughnee 'anhum minal laahi min shai'in illaa haajatan fee nafsi Ya'qooba qadaahaa; wa innahoo lazoo 'ilmil limaa 'allamnaahu wa laakinna aksaran naasi laa ya'lamoon", english: "And when they entered in the manner their father had enjoined, it did not profit them in the least against (the plan of) Allah: It was but a necessity of Jacob's soul, which he discharged. For he was, by our instruction, full of knowledge (and experience): but most men know not", romanUrdu: "Aur waqia bhi yahi hua ke jab woh apne baap ki hidayat ke mutabiq shehar mein (mutafarriq darwazon se) dakhil huey to uski yeh ehtiyati tadbeer Allah ki mashiyat ke muqable mein kuch bhi kaam na aa saki. Haan bas Yaqub ke dil mein jo ek khatak thi usey door karne ke liye usne apni si koshish karli. Beshak woh hamari di hui taleem se saahib-e-ilam tha magar aksar log maamle ki haqeeqat ko jaante nahin hain" },
    { number: 69, arabic: "وَلَمَّا دَخَلُوا۟ عَلَىٰ يُوسُفَ ءَاوَىٰٓ إِلَيْهِ أَخَاهُ ۖ قَالَ إِنِّىٓ أَنَا۠ أَخُوكَ فَلَا تَبْتَئِسْ بِمَا كَانُوا۟ يَعْمَلُونَ", transliteration: "Walamma dakhaloo AAala yoosufa awa ilayhi akhahu qala innee ana akhooka fala tabtais bima kanoo yaAAmaloona", transliterationB: "Wa lammaa dakhaloo 'alaa Yoosufa aawaaa ilaihi akhaahu qaala inneee ana akhooka falaa tabta'is bimaa kaanoo ya'maloon", english: "Now when they came into Joseph's presence, he received his (full) brother to stay with him. He said (to him): \"Behold! I am thy (own) brother; so grieve not at aught of their doings", romanUrdu: "Yeh log Yusuf ke huzoor pahunchey to usne apne bhai ko apne paas alag bula liya aur usey bata diya ke “ main tera wahi bhai hoon (jo khoya gaya tha). Ab tu un baaton ka gham na kar jo yeh log karte rahey hain.”" },
    { number: 70, arabic: "فَلَمَّا جَهَّزَهُم بِجَهَازِهِمْ جَعَلَ ٱلسِّقَايَةَ فِى رَحْلِ أَخِيهِ ثُمَّ أَذَّنَ مُؤَذِّنٌ أَيَّتُهَا ٱلْعِيرُ إِنَّكُمْ لَسَٰرِقُونَ", transliteration: "Falamma jahhazahum bijahazihim jaAAala alssiqayata fee rahli akheehi thumma aththana muaththinun ayyatuha alAAeeru innakum lasariqoona", transliterationB: "Falammaa jahhazahum bijahaazihim ja'alas siqaayata fee rahli akheehi summa azzana mu'azzinun ayyatuhal'eeru innakum lasaariqoon", english: "At length when he had furnished them forth with provisions (suitable) for them, he put the drinking cup into his brother's saddle-bag. Then shouted out a crier: \"O ye (in) the caravan! behold! ye are thieves, without doubt", romanUrdu: "Jab Yusuf in bhaiyon ka samaan ladhwane (loading) laga to usne apne bhai ke samaan mein apna pyala (cup) rakh diya. Phir ek pukarne waley ne pukar kar kaha “aey kafile walon, tum log chor ho.”" },
    { number: 71, arabic: "قَالُوا۟ وَأَقْبَلُوا۟ عَلَيْهِم مَّاذَا تَفْقِدُونَ", transliteration: "Qaloo waaqbaloo AAalayhim matha tafqidoona", transliterationB: "Qaaloo wa aqbaloo 'alaihim maazaa tafqidoon", english: "They said, turning towards them: \"What is it that ye miss", romanUrdu: "Unhon ne palat kar pucha “tumhari kya cheez khoi gayi?”" },
    { number: 72, arabic: "قَالُوا۟ نَفْقِدُ صُوَاعَ ٱلْمَلِكِ وَلِمَن جَآءَ بِهِۦ حِمْلُ بَعِيرٍۢ وَأَنَا۠ بِهِۦ زَعِيمٌۭ", transliteration: "Qaloo nafqidu suwaAAa almaliki waliman jaa bihi himlu baAAeerin waana bihi zaAAeemun", transliterationB: "Qaaloo nafqidu suwaa'al maliki wa liman jaaa'a bihee himlu ba'eerinw wa ana bihee za'eem", english: "They said: \"We miss the great beaker of the king; for him who produces it, is (the reward of) a camel load; I will be bound by it", romanUrdu: "Sarkari mulazimon ne kaha “baadshah ka paimana humko nahin milta” [aur unke jamadar (headman) ne kaha] “jo shaks laakar dega uske liye ek barishutar (camel load of corn) inaam hai, iska main zimma leta hoon.”" },
    { number: 73, arabic: "قَالُوا۟ تَٱللَّهِ لَقَدْ عَلِمْتُم مَّا جِئْنَا لِنُفْسِدَ فِى ٱلْأَرْضِ وَمَا كُنَّا سَٰرِقِينَ", transliteration: "Qaloo taAllahi laqad AAalimtum ma jina linufsida fee alardi wama kunna sariqeena", transliterationB: "Qaaloo tallaahi laqad 'alimtum maa ji'na linufsida fil ardi wa maa kunnaa saariqeen", english: "(The brothers) said: \"By Allah! well ye know that we came not to make mischief in the land, and we are no thieves", romanUrdu: "Un bhaiyon ne kaha “khuda ki kasam tum log khoob jaante ho ke hum is mulk mein fasad karne nahin aaye hain, aur hum choriyan karne waley log nahin hain”" },
    { number: 74, arabic: "قَالُوا۟ فَمَا جَزَٰٓؤُهُۥٓ إِن كُنتُمْ كَٰذِبِينَ", transliteration: "Qaloo fama jazaohu in kuntum kathibeena", transliterationB: "Qaaloo famaa jazaaa'u hooo in kuntum kaazibeen", english: "(The Egyptians) said: \"What then shall be the penalty of this, if ye are (proved) to have lied", romanUrdu: "Unhon ne kaha “accha, agar tumhari baat jhooti nikli to chor ki kya saza hai?”" },
    { number: 75, arabic: "قَالُوا۟ جَزَٰٓؤُهُۥ مَن وُجِدَ فِى رَحْلِهِۦ فَهُوَ جَزَٰٓؤُهُۥ ۚ كَذَٰلِكَ نَجْزِى ٱلظَّٰلِمِينَ", transliteration: "Qaloo jazaohu man wujida fee rahlihi fahuwa jazaohu kathalika najzee alththalimeena", transliterationB: "Qaaloo jazaaa'uhoo manw wujida fee rahlihee fahuwa jazaaa'uh; kazaalika najziz zaalimeen", english: "They said: \"The penalty should be that he in whose saddle-bag it is found, should be held (as bondman) to atone for the (crime). Thus it is we punish the wrong-doers", romanUrdu: "Unhon ne kaha “uski saza? Jiske samaan mein se cheez nikle woh aap hi apni saza mein rakh liya jaye, hamare haan to aise zalimon ko saza dene ka yahi tareeqa hai.”" },
    { number: 76, arabic: "فَبَدَأَ بِأَوْعِيَتِهِمْ قَبْلَ وِعَآءِ أَخِيهِ ثُمَّ ٱسْتَخْرَجَهَا مِن وِعَآءِ أَخِيهِ ۚ كَذَٰلِكَ كِدْنَا لِيُوسُفَ ۖ مَا كَانَ لِيَأْخُذَ أَخَاهُ فِى دِينِ ٱلْمَلِكِ إِلَّآ أَن يَشَآءَ ٱللَّهُ ۚ نَرْفَعُ دَرَجَٰتٍۢ مَّن نَّشَآءُ ۗ وَفَوْقَ كُلِّ ذِى عِلْمٍ عَلِيمٌۭ", transliteration: "Fabadaa biawAAiyatihim qabla wiAAai akheehi thumma istakhrajaha min wiAAai akheehi kathalika kidna liyoosufa ma kana liyakhutha akhahu fee deeni almaliki illa an yashaa Allahu narfaAAu darajatin man nashao wafawqa kulli thee AAilmin AAaleemun", transliterationB: "Fabada-a bi-aw'iyatihim qabla wi'aaa'i akheehi summas takhrajahaa minw wi 'aaa'i akheeh; kazaalika kidnaa li Yoosuf; maa kaana liyaakhuza akhaahu fee deenil maliki illaaa any yashaaa'al laah; narfa'u darajaatim man nashaaa'; wa fawqa kulli zee 'ilmin 'Aleem", english: "So he began (the search) with their baggage, before (he came to) the baggage of his brother: at length he brought it out of his brother's baggage. Thus did We plan for Joseph. He could not take his brother by the law of the king except that Allah willed it (so). We raise to degrees (of wisdom) whom We please: but over all endued with knowledge is one, the All-Knowing", romanUrdu: "Tab Yusuf ne apne bhai se pehle unki khurjhiyon (packs) ki talashi lena shuru ki. Phir apne bhai ki khurjhi (pack) se gumshuda cheez baramad karli. Is tarah humne Yusuf ki taeed (support) apni tadbeer se ki , uska yeh kaam na tha ke baadshah ke deen ( yani Misr ki shahi kanoon) mein apne bhai ko pakadta illa yeh ke Allah hi aisa chahe. Hum jiske darje chahte hain buland kardete hain, aur ek ilm rakhne wala aisa hai jo har sahib-e-ilam se balaa-tarr hai" },
    { number: 77, arabic: "۞ قَالُوٓا۟ إِن يَسْرِقْ فَقَدْ سَرَقَ أَخٌۭ لَّهُۥ مِن قَبْلُ ۚ فَأَسَرَّهَا يُوسُفُ فِى نَفْسِهِۦ وَلَمْ يُبْدِهَا لَهُمْ ۚ قَالَ أَنتُمْ شَرٌّۭ مَّكَانًۭا ۖ وَٱللَّهُ أَعْلَمُ بِمَا تَصِفُونَ", transliteration: "Qaloo in yasriq faqad saraqa akhun lahu min qablu faasarraha yoosufu fee nafsihi walam yubdiha lahum qala antum sharrun makanan waAllahu aAAlamu bima tasifoona", transliterationB: "Qaaloo iny yasriq faqad saraqa akhul lahoo min qabl; fa asarrahaa Yoosufu fee nafsihee wa lam yubdihaa lahum; qaala antum sharrum makaananw wallaahu a'lamu bimaa tasifoon", english: "They said: \"If he steals, there was a brother of his who did steal before (him).\" But these things did Joseph keep locked in his heart, revealing not the secrets to them. He (simply) said (to himself): \"Ye are the worse situated; and Allah knoweth best the truth of what ye assert", romanUrdu: "Un bhaiyon ne kaha “yeh chori karey to kuch taajub ki baat bhi nahin, issey pehle iska bhai (Yusuf) bhi chori kar chuka hai”. Yusuf unki yeh baat sunkar pee gyaa (suppressed his feelings) haqeeqat unpar na kholi , bas (zeri-e-lab) itna kehkar reh gaya ke “badey hi burey ho tumlog, (mere mooh dar mooh mujhpar) jo ilzaam tum laga rahey ho uski haqeeqat khuda khoob jaanta hai”" },
    { number: 78, arabic: "قَالُوا۟ يَٰٓأَيُّهَا ٱلْعَزِيزُ إِنَّ لَهُۥٓ أَبًۭا شَيْخًۭا كَبِيرًۭا فَخُذْ أَحَدَنَا مَكَانَهُۥٓ ۖ إِنَّا نَرَىٰكَ مِنَ ٱلْمُحْسِنِينَ", transliteration: "Qaloo ya ayyuha alAAazeezu inna lahu aban shaykhan kabeeran fakhuth ahadana makanahu inna naraka mina almuhsineena", transliterationB: "Qaaloo yaaa ayyuhal 'Azeezu inna lahooo aban shaikhan kabeeran fakhuz ahadanaa makaanahoo innaa naraaka minal muhsineen", english: "They said: \"O exalted one! Behold! he has a father, aged and venerable, (who will grieve for him); so take one of us in his place; for we see that thou art (gracious) in doing good", romanUrdu: "Unhon ne kaha “aey sardar zi-iqtedar (Aziz), iska baap bahut booda aadmi hai, iski jagah aap hum mein se kisi ko rakh lijiye. Hum aapko bada hi neik nafs Insaan patey hain.”" },
    { number: 79, arabic: "قَالَ مَعَاذَ ٱللَّهِ أَن نَّأْخُذَ إِلَّا مَن وَجَدْنَا مَتَٰعَنَا عِندَهُۥٓ إِنَّآ إِذًۭا لَّظَٰلِمُونَ", transliteration: "Qala maAAatha Allahi an nakhutha illa man wajadna mataAAana AAindahu inna ithan lathalimoona", transliterationB: "Qaala ma'aazal laahi an naakhuza illaa manw wajadnaa mataa'anaa 'indahoo innaaa izal lazaalimoon", english: "He said: \"Allah forbid that we take other than him with whom we found our property: indeed (if we did so), we should be acting wrongfully", romanUrdu: "Yusuf ne kaha “panaah ba khuda, dusre kisi shaks ko hum kaise rakh sakte hain, jiske paas humne apna maal paya hai usko chodh kar dusre ko rakkhenge to hum zalim hongey.”" },
    { number: 80, arabic: "فَلَمَّا ٱسْتَيْـَٔسُوا۟ مِنْهُ خَلَصُوا۟ نَجِيًّۭا ۖ قَالَ كَبِيرُهُمْ أَلَمْ تَعْلَمُوٓا۟ أَنَّ أَبَاكُمْ قَدْ أَخَذَ عَلَيْكُم مَّوْثِقًۭا مِّنَ ٱللَّهِ وَمِن قَبْلُ مَا فَرَّطتُمْ فِى يُوسُفَ ۖ فَلَنْ أَبْرَحَ ٱلْأَرْضَ حَتَّىٰ يَأْذَنَ لِىٓ أَبِىٓ أَوْ يَحْكُمَ ٱللَّهُ لِى ۖ وَهُوَ خَيْرُ ٱلْحَٰكِمِينَ", transliteration: "Falamma istayasoo minhu khalasoo najiyyan qala kabeeruhum alam taAAlamoo anna abakum qad akhatha AAalaykum mawthiqan mina Allahi wamin qablu ma farrattum fee yoosufa falan abraha alarda hatta yathana lee abee aw yahkuma Allahu lee wahuwa khayru alhakimeena", transliterationB: "Falammas tay'asoo minhu khalasoo najiyyan qaala kabeeruhum alam ta'lamoon anna abaakum qad akhaza 'alaikum mawsiqam minal laahi wa min qablu maa farrattum fee Yoosufa falan abrahal arda hattaa yaazana leee abeee aw yahkumal laahu lee wa huwa khairul lhaakimeen", english: "Now when they saw no hope of his (yielding), they held a conference in private. The leader among them said: \"Know ye not that your father did take an oath from you in Allah's name, and how, before this, ye did fail in your duty with Joseph? Therefore will I not leave this land until my father permits me, or Allah commands me; and He is the best to command", romanUrdu: "Jab woh Yusuf se mayous ho gaye to ek goshey mein jaa kar aapas mein mashwara karne lagey. Un mein jo sabse bada tha woh bola “tum jantey nahin ho ke tumhare walid tumse khuda ke naam par kya ahad o paiman le chuke hain, aur issey pehle Yusuf ke maamle mein jo zyadati tum kar chuke ho woh bhi tumko maloom hai. Ab main to yahan se hargiz na jaunga jab tak ke mere walid mujhey ijazat na dein, ya phir Allah hi mere haqq mein koi faisla farma de, ke woh sab se behtar faisla karne wala hai" },
    { number: 81, arabic: "ٱرْجِعُوٓا۟ إِلَىٰٓ أَبِيكُمْ فَقُولُوا۟ يَٰٓأَبَانَآ إِنَّ ٱبْنَكَ سَرَقَ وَمَا شَهِدْنَآ إِلَّا بِمَا عَلِمْنَا وَمَا كُنَّا لِلْغَيْبِ حَٰفِظِينَ", transliteration: "IrjiAAoo ila abeekum faqooloo ya abana inna ibnaka saraqa wama shahidna illa bima AAalimna wama kunna lilghaybi hafitheena", transliterationB: "Irji'ooo ilaaa abeekum faqooloo yaaa abaanaaa innab naka saraq; wa maa shahidnaaa illaa bimaa 'alimnaa wa maa kunnaa lilghaibi haafizeen", english: "Turn ye back to your father, and say, 'O our father! behold! thy son committed theft! we bear witness only to what we know, and we could not well guard against the unseen", romanUrdu: "Tum jaa kar apne walid se kaho ke “abbajaan , aapke sahibzadey ne chori ki hai. Humne usey chori karte huey nahin dekha, jo kuch humein maloom hua hai bas wahi hum bayan kar rahey hain, aur gaib ki nigehbani to hum na kar sakte thay" },
    { number: 82, arabic: "وَسْـَٔلِ ٱلْقَرْيَةَ ٱلَّتِى كُنَّا فِيهَا وَٱلْعِيرَ ٱلَّتِىٓ أَقْبَلْنَا فِيهَا ۖ وَإِنَّا لَصَٰدِقُونَ", transliteration: "Waisali alqaryata allatee kunna feeha waalAAeera allatee aqbalna feeha wainna lasadiqoona", transliterationB: "Was'alil qaryatal latee kunnaa feehaa wal'eeral lateee aqbalnaa feehaa wa innaa lasaadiqoon", english: "Ask at the town where we have been and the caravan in which we returned, and (you will find) we are indeed telling the truth", romanUrdu: "Aap us basti ke logon se puch lijiye jahan hum thay us kafile se daryaft kar lijiye jiske saath hum aaye hain. Hum apne bayan mein bilkul sacchey hain.”" },
    { number: 83, arabic: "قَالَ بَلْ سَوَّلَتْ لَكُمْ أَنفُسُكُمْ أَمْرًۭا ۖ فَصَبْرٌۭ جَمِيلٌ ۖ عَسَى ٱللَّهُ أَن يَأْتِيَنِى بِهِمْ جَمِيعًا ۚ إِنَّهُۥ هُوَ ٱلْعَلِيمُ ٱلْحَكِيمُ", transliteration: "Qala bal sawwalat lakum anfusukum amran fasabrun jameelun AAasa Allahu an yatiyanee bihim jameeAAan innahu huwa alAAaleemu alhakeemu", transliterationB: "Qaala bal sawwalat lakum anfusukum amran fasabrun jameelun 'asal laahu any yaa tiyanee bihim jamee'aa; innahoo Huwal 'Aleemul Hakeem", english: "Jacob said: \"Nay, but ye have yourselves contrived a story (good enough) for you. So patience is most fitting (for me). Maybe Allah will bring them (back) all to me (in the end). For He is indeed full of knowledge and wisdom", romanUrdu: "Baap ne yeh daastan sun kar kaha “ dar-asal tumahre nafs ne tumhare liye ek aur badi baat ko sahal(aasaan) bana diya. Accha ispar bhi sabr karunga aur bakhubi karunga. Kya baeed hai ke Allah un sab ko mujhse laa milaye, woh sab kuch jaanta hai aur uske sab kaam hikmat par mabni hain.”" },
    { number: 84, arabic: "وَتَوَلَّىٰ عَنْهُمْ وَقَالَ يَٰٓأَسَفَىٰ عَلَىٰ يُوسُفَ وَٱبْيَضَّتْ عَيْنَاهُ مِنَ ٱلْحُزْنِ فَهُوَ كَظِيمٌۭ", transliteration: "Watawalla AAanhum waqala ya asafa AAala yoosufa waibyaddat AAaynahu mina alhuzni fahuwa katheemun", transliterationB: "Wa tawallaa 'anhum wa qaala yaaa asafaa 'alaa Yoosufa wabyaddat 'aynaahu minal huzni fahuwa kazeem", english: "And he turned away from them, and said: \"How great is my grief for Joseph!\" And his eyes became white with sorrow, and he fell into silent melancholy", romanUrdu: "Phir woh unki taraf se mooh pher kar baith gaya aur kehne laga ke “haaye Yusuf!” woh dil hi dil mein gham se ghuta jaa raha tha aur uski aankhein safed padh gayi thi" },
    { number: 85, arabic: "قَالُوا۟ تَٱللَّهِ تَفْتَؤُا۟ تَذْكُرُ يُوسُفَ حَتَّىٰ تَكُونَ حَرَضًا أَوْ تَكُونَ مِنَ ٱلْهَٰلِكِينَ", transliteration: "Qaloo taAllahi taftao tathkuru yoosufa hatta takoona haradan aw takoona mina alhalikeena", transliterationB: "Qaaloo tallaahi tafta'u tazkuru Yoosufa hattaa takoona haradan aw takoona minal haalikeen", english: "They said: \"By Allah! (never) wilt thou cease to remember Joseph until thou reach the last extremity of illness, or until thou die", romanUrdu: "Beton ne kaha “khuda-ra! Aap to bas Yusuf hi ko yaad kiye jatey hain naubat yeh aa gayi hai ke uske ghum mein apne aap ko ghula dein ya apni jaan halaak kar daalenge.”" },
    { number: 86, arabic: "قَالَ إِنَّمَآ أَشْكُوا۟ بَثِّى وَحُزْنِىٓ إِلَى ٱللَّهِ وَأَعْلَمُ مِنَ ٱللَّهِ مَا لَا تَعْلَمُونَ", transliteration: "Qala innama ashkoo baththee wahuznee ila Allahi waaAAlamu mina Allahi ma la taAAlamoona", transliterationB: "Qaala innamaaa ashkoo bassee wa huzneee ilal laahi wa a'lamu minal laahi maa laa ta'lamoon", english: "He said: \"I only complain of my distraction and anguish to Allah, and I know from Allah that which ye know not", romanUrdu: "Usne kaha “ main apni pareshani aur apne gham ki fariyad Allah ke siwa kisi se nahin karta. Aur Allah se jaisa main waqif hoon tum nahin ho" },
    { number: 87, arabic: "يَٰبَنِىَّ ٱذْهَبُوا۟ فَتَحَسَّسُوا۟ مِن يُوسُفَ وَأَخِيهِ وَلَا تَا۟يْـَٔسُوا۟ مِن رَّوْحِ ٱللَّهِ ۖ إِنَّهُۥ لَا يَا۟يْـَٔسُ مِن رَّوْحِ ٱللَّهِ إِلَّا ٱلْقَوْمُ ٱلْكَٰفِرُونَ", transliteration: "Ya baniyya ithhaboo fatahassasoo min yoosufa waakheehi wala tayasoo min rawhi Allahi innahu la yayasu min rawhi Allahi illa alqawmu alkafiroona", transliterationB: "Yaa baniyyaz haboo fatahassasoo miny Yoosufa wa akheehi wa laa tai'asoo mir rawhil laahi innahoo laa yai'asu mir rawhil laahi illal qawmul kaafiroon", english: "O my sons! go ye and enquire about Joseph and his brother, and never give up hope of Allah's Soothing Mercy: truly no one despairs of Allah's Soothing Mercy, except those who have no faith", romanUrdu: "Mere bacchon, jaa kar Yusuf aur uske bhai ki kuch tohh lagao (make a search). Allah ki rehmat se mayous na ho, uski rehmat se to bas kafir hi mayous hua karte hain.”" },
    { number: 88, arabic: "فَلَمَّا دَخَلُوا۟ عَلَيْهِ قَالُوا۟ يَٰٓأَيُّهَا ٱلْعَزِيزُ مَسَّنَا وَأَهْلَنَا ٱلضُّرُّ وَجِئْنَا بِبِضَٰعَةٍۢ مُّزْجَىٰةٍۢ فَأَوْفِ لَنَا ٱلْكَيْلَ وَتَصَدَّقْ عَلَيْنَآ ۖ إِنَّ ٱللَّهَ يَجْزِى ٱلْمُتَصَدِّقِينَ", transliteration: "Falamma dakhaloo AAalayhi qaloo ya ayyuha alAAazeezu massana waahlana alddurru wajina bibidaAAatin muzjatin faawfi lana alkayla watasaddaq AAalayna inna Allaha yajzee almutasaddiqeena", transliterationB: "Falammaa dakhaloo 'alaihi qaaloo yaaa ayyuhal 'Azeezu massanaa wa ahlanad durru wa ji'naa bibidaa 'timmuzjaatin fa awfi lanal kaila wa tasaddaq 'alainaa innal laaha yajzil mutasaddiqeen", english: "Then, when they came (back) into (Joseph's) presence they said: \"O exalted one! distress has seized us and our family: we have (now) brought but scanty capital: so pay us full measure, (we pray thee), and treat it as charity to us: for Allah doth reward the charitable", romanUrdu: "Jab yeh log Misr jaa kar Yusuf ki peshi mein dakhil huey to unhon ne arz kiya ke “aey sardar ba iqtedar , hum aur hamare ehal o ayal sakht museebat mein mubtala hain aur hum kuch hakeer si poonji lekar aaye hain, aap humein bharpur galla inayat farmayein aur humko khairaat dein, Allah khairaat karne walon ko jaza deta hai.”" },
    { number: 89, arabic: "قَالَ هَلْ عَلِمْتُم مَّا فَعَلْتُم بِيُوسُفَ وَأَخِيهِ إِذْ أَنتُمْ جَٰهِلُونَ", transliteration: "Qala hal AAalimtum ma faAAaltum biyoosufa waakheehi ith antum jahiloona", transliterationB: "Qaala hal 'alimtum maa fa'altum bi Yoosufa wa akheehi iz antum jaahiloon", english: "He said: \"Know ye how ye dealt with Joseph and his brother, not knowing (what ye were doing)", romanUrdu: "(Yeh sunkar Yusuf se na raha gaya) usne kaha, “tumhein kuch yeh bhi maaloom hai ke tumne Yusuf aur uske bhai ke saath kya kiya tha jabke tum nadaan thay.”" },
    { number: 90, arabic: "قَالُوٓا۟ أَءِنَّكَ لَأَنتَ يُوسُفُ ۖ قَالَ أَنَا۠ يُوسُفُ وَهَٰذَآ أَخِى ۖ قَدْ مَنَّ ٱللَّهُ عَلَيْنَآ ۖ إِنَّهُۥ مَن يَتَّقِ وَيَصْبِرْ فَإِنَّ ٱللَّهَ لَا يُضِيعُ أَجْرَ ٱلْمُحْسِنِينَ", transliteration: "Qaloo ainnaka laanta yoosufa qala ana yoosufu wahatha akhee qad manna Allahu AAalayna innahu man yattaqi wayasbir fainna Allaha la yudeeAAu ajra almuhsineena", transliterationB: "Qaaloo 'a innaka la anta Yoosufu qaala ana Yoosufu wa haazaaa akhee qad mannal laahu 'alainaa innahoo mai yattaqi wa yasbir fa innal laaha laa yudee'u ajral muhsineen", english: "They said: \"Art thou indeed Joseph?\" He said, \"I am Joseph, and this is my brother: Allah has indeed been gracious to us (all): behold, he that is righteous and patient,- never will Allah suffer the reward to be lost, of those who do right", romanUrdu: "Woh chaunk kar bole “kya tum Yusuf ho?” usne kaha, “haan , main Yusuf hoon aur yeh mera bhai hai. Allah ne humpar ehsan farmaya. Haqeeqat yeh hai ke agar koi taqwa aur sabr se kaam ley to Allah ke haan aise neik logon ka ajar maara nahin jata.”" },
    { number: 91, arabic: "قَالُوا۟ تَٱللَّهِ لَقَدْ ءَاثَرَكَ ٱللَّهُ عَلَيْنَا وَإِن كُنَّا لَخَٰطِـِٔينَ", transliteration: "Qaloo taAllahi laqad atharaka Allahu AAalayna wain kunna lakhatieena", transliterationB: "Qaaloo tallaahi laqad aasarakal laahu 'alainaa wa in kunnaa lakhaati'een", english: "They said: \"By Allah! indeed has Allah preferred thee above us, and we certainly have been guilty of sin", romanUrdu: "Unhon ne kaha “ba-khuda ke tumko Allah ne humpar fazilat bakshi aur waqayi hum khatakaar thay.”" },
    { number: 92, arabic: "قَالَ لَا تَثْرِيبَ عَلَيْكُمُ ٱلْيَوْمَ ۖ يَغْفِرُ ٱللَّهُ لَكُمْ ۖ وَهُوَ أَرْحَمُ ٱلرَّٰحِمِينَ", transliteration: "Qala la tathreeba AAalaykumu alyawma yaghfiru Allahu lakum wahuwa arhamu alrrahimeena", transliterationB: "Qaala laa tasreeba 'alaikumul yawma yaghfirul laahu lakum wa Huwa arhamur raahimeen", english: "He said: \"This day let no reproach be (cast) on you: Allah will forgive you, and He is the Most Merciful of those who show mercy", romanUrdu: "Usne jawab diya, “aaj tumpar koi giraft nahin , Allah tumhein maaf karey, woh sab se badhkar reham farmane wala hai" },
    { number: 93, arabic: "ٱذْهَبُوا۟ بِقَمِيصِى هَٰذَا فَأَلْقُوهُ عَلَىٰ وَجْهِ أَبِى يَأْتِ بَصِيرًۭا وَأْتُونِى بِأَهْلِكُمْ أَجْمَعِينَ", transliteration: "Ithhaboo biqameesee hatha faalqoohu AAala wajhi abee yati baseeran watoonee biahlikum ajmaAAeena", transliterationB: "Izhaboo biqameesee haazaa fa alqoohu 'alaa wajhi abee yaati baseeranw waatoonee bi ahlikum ajma'een", english: "Go with this my shirt, and cast it over the face of my father: he will come to see (clearly). Then come ye (here) to me together with all your family", romanUrdu: "Jao, mera yeh kamees le jao aur mere walid ke mooh par daal do, unki binayi palat aayegi. Aur apne sab ehal-o-ayal ko mere paas le aao.”" },
    { number: 94, arabic: "وَلَمَّا فَصَلَتِ ٱلْعِيرُ قَالَ أَبُوهُمْ إِنِّى لَأَجِدُ رِيحَ يُوسُفَ ۖ لَوْلَآ أَن تُفَنِّدُونِ", transliteration: "Walamma fasalati alAAeeru qala aboohum innee laajidu reeha yoosufa lawla an tufannidooni", transliterationB: "Wa lammaa fasalatil 'eeru qaala aboohum innee la ajidu reeha Yoosufa law laaa an tufannidoon", english: "When the caravan left (Egypt), their father said: \"I do indeed scent the presence of Joseph: Nay, think me not a dotard", romanUrdu: "Jab yeh kafila (Misr se) rawana hua to unke baap ne (kanaan mein) kaha “main Yusuf ki khusboo mehsoos kar raha hoon, tum log kahin yeh na kehne lago ke main budhape mein satiya gaya hoon.”" },
    { number: 95, arabic: "قَالُوا۟ تَٱللَّهِ إِنَّكَ لَفِى ضَلَٰلِكَ ٱلْقَدِيمِ", transliteration: "Qaloo taAllahi innaka lafee dalalika alqadeemi", transliterationB: "Qaaloo tallaahi innaka lafee dalaalikal qadeem", english: "They said: \"By Allah! truly thou art in thine old wandering mind", romanUrdu: "Ghar ke log bole “khuda ki kasam aap abhi tak apne usi purane khabt (old illusion) mein padey huey hain”" },
    { number: 96, arabic: "فَلَمَّآ أَن جَآءَ ٱلْبَشِيرُ أَلْقَىٰهُ عَلَىٰ وَجْهِهِۦ فَٱرْتَدَّ بَصِيرًۭا ۖ قَالَ أَلَمْ أَقُل لَّكُمْ إِنِّىٓ أَعْلَمُ مِنَ ٱللَّهِ مَا لَا تَعْلَمُونَ", transliteration: "Falamma an jaa albasheeru alqahu AAala wajhihi fairtadda baseeran qala alam aqul lakum innee aAAlamu mina Allahi ma la taAAlamoona", transliterationB: "Falammaaa an jaaa'albasheeru alqaahu 'alaa wajhihee fartadda baseeran qaala alam aqul lakum inneee a'lamu minal laahi maa laa ta'lamoon", english: "Then when the bearer of the good news came, He cast (the shirt) over his face, and he forthwith regained clear sight. He said: \"Did I not say to you, 'I know from Allah that which ye know not", romanUrdu: "Phir jab khush-khabri laney wala aaya to usne Yusuf ka kamees Yaqub ke mooh par daal diya aur yakayak uski binayi oad kar aayi (sight carne back to him) . Tab usne kaha “main tumse kehta na tha main Allah ki taraf se woh kuch jaanta hoon jo tum nahin jantey.”" },
    { number: 97, arabic: "قَالُوا۟ يَٰٓأَبَانَا ٱسْتَغْفِرْ لَنَا ذُنُوبَنَآ إِنَّا كُنَّا خَٰطِـِٔينَ", transliteration: "Qaloo ya abana istaghfir lana thunoobana inna kunna khatieena", transliterationB: "Qaaloo yaaa abaanas taghfir lanaa zunoo =banaaa innaa kunnaa khaati'een", english: "They said: \"O our father! ask for us forgiveness for our sins, for we were truly at fault", romanUrdu: "Sab bol utthey “abbajaan, aap hamare gunaahon ki bakshish ke liye dua karein, waqayi hum khatakaar thay.”" },
    { number: 98, arabic: "قَالَ سَوْفَ أَسْتَغْفِرُ لَكُمْ رَبِّىٓ ۖ إِنَّهُۥ هُوَ ٱلْغَفُورُ ٱلرَّحِيمُ", transliteration: "Qala sawfa astaghfiru lakum rabbee innahu huwa alghafooru alrraheemu", transliterationB: "Qaala sawfa astaghfiru lakum Rabbeee innahoo Huwal Ghafoorur Raheem", english: "He said: \"Soon will I ask my Lord for forgiveness for you: for he is indeed Oft-Forgiving, Most Merciful", romanUrdu: "Usne kaha ‘main apne Rubb se tumhare liye maafi ki darkhwast karunga, woh bada maaf karne wala aur raheem hai.”" },
    { number: 99, arabic: "فَلَمَّا دَخَلُوا۟ عَلَىٰ يُوسُفَ ءَاوَىٰٓ إِلَيْهِ أَبَوَيْهِ وَقَالَ ٱدْخُلُوا۟ مِصْرَ إِن شَآءَ ٱللَّهُ ءَامِنِينَ", transliteration: "Falamma dakhaloo AAala yoosufa awa ilayhi abawayhi waqala odkhuloo misra in shaa Allahu amineena", transliterationB: "Falammaa dakhaloo 'alaa Yoosufa aawaaa ilaihi abayaihi wa qaalad khuloo Misra inshaaa'al laahu aamineen", english: "Then when they entered the presence of Joseph, he provided a home for his parents with himself, and said: \"Enter ye Egypt (all) in safety if it please Allah", romanUrdu: "Phir jab yeh log Yusuf ke paas pahunche to usne apne walidain ko apne saath bitha liya aur (apne sab kumbe walon se ) kaha “ chalo ab shehar mein chalo, Allah ne chaha to aman chain se rahoge.”" },
    { number: 100, arabic: "وَرَفَعَ أَبَوَيْهِ عَلَى ٱلْعَرْشِ وَخَرُّوا۟ لَهُۥ سُجَّدًۭا ۖ وَقَالَ يَٰٓأَبَتِ هَٰذَا تَأْوِيلُ رُءْيَٰىَ مِن قَبْلُ قَدْ جَعَلَهَا رَبِّى حَقًّۭا ۖ وَقَدْ أَحْسَنَ بِىٓ إِذْ أَخْرَجَنِى مِنَ ٱلسِّجْنِ وَجَآءَ بِكُم مِّنَ ٱلْبَدْوِ مِنۢ بَعْدِ أَن نَّزَغَ ٱلشَّيْطَٰنُ بَيْنِى وَبَيْنَ إِخْوَتِىٓ ۚ إِنَّ رَبِّى لَطِيفٌۭ لِّمَا يَشَآءُ ۚ إِنَّهُۥ هُوَ ٱلْعَلِيمُ ٱلْحَكِيمُ", transliteration: "WarafaAAa abawayhi AAala alAAarshi wakharroo lahu sujjadan waqala ya abati hatha taweelu ruyaya min qablu qad jaAAalaha rabbee haqqan waqad ahsana bee ith akhrajanee mina alssijni wajaa bikum mina albadwi min baAAdi an nazagha alshshaytanu baynee wabayna ikhwatee inna rabbee lateefun lima yashao innahu huwa alAAaleemu alhakeemu", transliterationB: "Wa raf'a abawaihi 'alal 'arshi wa kharroo lahoo sujjadaa; wa qaala yaaa abati haaza taaweelu ru'yaaya min qablu qad ja'alahaa Rabbee haqqaa; wa qad ahsana beee iz akhrajanee minas sijni wa jaaa'a bikum minal badwi mim ba'di an nazaghash Shaitaanu bainee wa baina ikhwatee; inna Rabbee lateeful limaa yashaaa'; innahoo Huwal 'Aleemul Hakeem", english: "And he raised his parents high on the throne (of dignity), and they fell down in prostration, (all) before him. He said: \"O my father! this is the fulfilment of my vision of old! Allah hath made it come true! He was indeed good to me when He took me out of prison and brought you (all here) out of the desert, (even) after Satan had sown enmity between me and my brothers. Verily my Lord understandeth best the mysteries of all that He planneth to do, for verily He is full of knowledge and wisdom", romanUrdu: "(Shehar mein daakhil honay ke baad) usne apne walidain ko utha kar apne paas takht par bithaya aur sab uske aage be ikhtiyar sajde mein jhuk gaye. Yusuf ne kaha “abbajaan, yeh tabeer hai mere us khwab ki jo maine pehle dekha tha, mere Rubb ne usey haqeeqat bana diya. Uska ehsan hai ke usne mujhey qaid-khane se nikala aur aap logon ko sehra se laakar mujhse milaya, halanke shaytan mere aur mere bhaiyon ke darmiyan fasaad daal chuka tha. Waqiya yeh hai ke mera Rubb gair mehsoos tadbeeron (mysterious ways) se apni mashiyat puri karta hai, beshak woh aleem aur hakeem hai" },
    { number: 101, arabic: "۞ رَبِّ قَدْ ءَاتَيْتَنِى مِنَ ٱلْمُلْكِ وَعَلَّمْتَنِى مِن تَأْوِيلِ ٱلْأَحَادِيثِ ۚ فَاطِرَ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ أَنتَ وَلِىِّۦ فِى ٱلدُّنْيَا وَٱلْءَاخِرَةِ ۖ تَوَفَّنِى مُسْلِمًۭا وَأَلْحِقْنِى بِٱلصَّٰلِحِينَ", transliteration: "Rabbi qad ataytanee mina almulki waAAallamtanee min taweeli alahadeethi fatira alssamawati waalardi anta waliyyee fee alddunya waalakhirati tawaffanee musliman waalhiqnee bialssaliheena", transliterationB: "Rabbi qad aataitanee minal mulki wa 'allamtanee min taaweelil ahaadees; faati ras samaawaati wal ardi Anta waliyyee fid dunyaa wal Aakhirati tawaffanee muslimanw wa alhiqnee bissaaliheen", english: "O my Lord! Thou hast indeed bestowed on me some power, and taught me something of the interpretation of dreams and events,- O Thou Creator of the heavens and the earth! Thou art my Protector in this world and in the Hereafter. Take Thou my soul (at death) as one submitting to Thy will (as a Muslim), and unite me with the righteous", romanUrdu: "Aey mere Rubb, tu nay mujhey hukumat bakshi aur mujhko baaton ki teh tak pahunchna sikhaya. Zameen o aasmaan ke banane waley, tu hi duniya aur aakhirat mein mera sarparast hai, mera khatma Islam par kar aur anjaam e kaar mujhey saliheen ke saath mila”" },
    { number: 102, arabic: "ذَٰلِكَ مِنْ أَنۢبَآءِ ٱلْغَيْبِ نُوحِيهِ إِلَيْكَ ۖ وَمَا كُنتَ لَدَيْهِمْ إِذْ أَجْمَعُوٓا۟ أَمْرَهُمْ وَهُمْ يَمْكُرُونَ", transliteration: "Thalika min anbai alghaybi nooheehi ilayka wama kunta ladayhim ith ajmaAAoo amrahum wahum yamkuroona", transliterationB: "Zaalika min ambaaa'il ghaibi nooheehi ilaika wa maa kunta ladaihim iz ajma'ooo amrahum wa hum yamkuroon", english: "Such is one of the stories of what happened unseen, which We reveal by inspiration unto thee; nor wast thou (present) with them then when they concerted their plans together in the process of weaving their plots", romanUrdu: "(Aey Muhammad) yeh qissa gaib ki khabron mein se hai jo hum tumpar wahee kar rahey hain, warna tum us waqt maujood na thay jab Yusuf ke bhaiyon ne aapas mein ittefaq karke saazish ki thi" },
    { number: 103, arabic: "وَمَآ أَكْثَرُ ٱلنَّاسِ وَلَوْ حَرَصْتَ بِمُؤْمِنِينَ", transliteration: "Wama aktharu alnnasi walaw harasta bimumineena", transliterationB: "Wa maa aksarun naasi wa law harasta bimu'mineen", english: "Yet no faith will the greater part of mankind have, however ardently thou dost desire it", romanUrdu: "Magar tum khwa kitna hi chaho inmein se aksar log maan kar dene waley nahin hain" },
    { number: 104, arabic: "وَمَا تَسْـَٔلُهُمْ عَلَيْهِ مِنْ أَجْرٍ ۚ إِنْ هُوَ إِلَّا ذِكْرٌۭ لِّلْعَٰلَمِينَ", transliteration: "Wama tasaluhum AAalayhi min ajrin in huwa illa thikrun lilAAalameena", transliterationB: "Wa maa tas'aluhum 'alaihi min ajr; in huwa illaa zikrul lil'aalameen", english: "And no reward dost thou ask of them for this: it is no less than a message for all creatures", romanUrdu: "Halanke tum is khidmat par insey koi ujrat bhi nahin maangte ho, yeh to ek naseehat hai jo duniya walon ke liye aam hai" },
    { number: 105, arabic: "وَكَأَيِّن مِّنْ ءَايَةٍۢ فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ يَمُرُّونَ عَلَيْهَا وَهُمْ عَنْهَا مُعْرِضُونَ", transliteration: "Wakaayyin min ayatin fee alssamawati waalardi yamurroona AAalayha wahum AAanha muAAridoona", transliterationB: "Wa ka ayyim min Aayatin fis samaawaati wal ardi yamurroona 'alaihaa wa hum 'anhaa mu'ridoon", english: "And how many Signs in the heavens and the earth do they pass by? Yet they turn (their faces) away from them", romanUrdu: "Zameen aur aasmano mein kitni hi nishaniyan hain jinpar se yeh log guzarte rehte hain aur zara tawajju nahin karte" },
    { number: 106, arabic: "وَمَا يُؤْمِنُ أَكْثَرُهُم بِٱللَّهِ إِلَّا وَهُم مُّشْرِكُونَ", transliteration: "Wama yuminu aktharuhum biAllahi illa wahum mushrikoona", transliterationB: "Wa maa yu'minu aksaru hum billaahi illaa wa hum mushrikoon", english: "And most of them believe not in Allah without associating (other as partners) with Him", romanUrdu: "In mein se aksar Allah ko maante hain magar is tarah ke uske saath dusron ko shareek thehrate hain" },
    { number: 107, arabic: "أَفَأَمِنُوٓا۟ أَن تَأْتِيَهُمْ غَٰشِيَةٌۭ مِّنْ عَذَابِ ٱللَّهِ أَوْ تَأْتِيَهُمُ ٱلسَّاعَةُ بَغْتَةًۭ وَهُمْ لَا يَشْعُرُونَ", transliteration: "Afaaminoo an tatiyahum ghashiyatun min AAathabi Allahi aw tatiyahumu alssaAAatu baghtatan wahum la yashAAuroona", transliterationB: "Afa aminooo an taatiya hum ghaashiyatum min 'azaabil laahi aw taatiyahumus Saa'atu baghtatanw wa hum laa yash'uroon", english: "Do they then feel secure from the coming against them of the covering veil of the wrath of Allah,- or of the coming against them of the (final) Hour all of a sudden while they perceive not", romanUrdu: "Kya yeh mutmaeen hain ke khuda ke azaab ki koi balaa inhein daboch na legi ya bekhabri mein qayamat ki ghadi achanak inpar na aa jaayegi" },
    { number: 108, arabic: "قُلْ هَٰذِهِۦ سَبِيلِىٓ أَدْعُوٓا۟ إِلَى ٱللَّهِ ۚ عَلَىٰ بَصِيرَةٍ أَنَا۠ وَمَنِ ٱتَّبَعَنِى ۖ وَسُبْحَٰنَ ٱللَّهِ وَمَآ أَنَا۠ مِنَ ٱلْمُشْرِكِينَ", transliteration: "Qul hathihi sabeelee adAAoo ila Allahi AAala baseeratin ana wamani ittabaAAanee wasubhana Allahi wama ana mina almushrikeena", transliterationB: "Qul haazihee sabeeleee ad'ooo ilal laah; 'alaa baseera tin ana wa manit taba'anee wa Subhaanal laahi wa maaa ana minal mushrikeen", english: "Say thou: \"This is my way: I do invite unto Allah,- on evidence clear as the seeing with one's eyes,- I and whoever follows me. Glory to Allah! and never will I join gods with Allah", romanUrdu: "Tum insey saaf kehdo ke” mera rasta to yeh hai , main Allah ki taraf bulata hoon, main khud bhi puri roshni mein apna rasta dekh raha hoon aur mere saathi bhi, aur Allah paak hai aur shirk karne walon se mera koi waasta nahin.”" },
    { number: 109, arabic: "وَمَآ أَرْسَلْنَا مِن قَبْلِكَ إِلَّا رِجَالًۭا نُّوحِىٓ إِلَيْهِم مِّنْ أَهْلِ ٱلْقُرَىٰٓ ۗ أَفَلَمْ يَسِيرُوا۟ فِى ٱلْأَرْضِ فَيَنظُرُوا۟ كَيْفَ كَانَ عَٰقِبَةُ ٱلَّذِينَ مِن قَبْلِهِمْ ۗ وَلَدَارُ ٱلْءَاخِرَةِ خَيْرٌۭ لِّلَّذِينَ ٱتَّقَوْا۟ ۗ أَفَلَا تَعْقِلُونَ", transliteration: "Wama arsalna min qablika illa rijalan noohee ilayhim min ahli alqura afalam yaseeroo fee alardi fayanthuroo kayfa kana AAaqibatu allatheena min qablihim waladaru alakhirati khayrun lillatheena ittaqaw afala taAAqiloona", transliterationB: "Wa maaa arsalnaa min qablika illaa rijaalan nooheee ilaihim min ahlil quraa; afalam yaseeroo fil ardi fa yanzuroo kaifa kaana 'aaqibatul lazeena min qablihim; wa la Daarul Aakhirati Khairul lillazeenat taqaw; afalaa ta'qiloon", english: "Nor did We send before thee (as messengers) any but men, whom we did inspire,- (men) living in human habitations. Do they not travel through the earth, and see what was the end of those before them? But the home of the hereafter is best, for those who do right. Will ye not then understand", romanUrdu: "(Aey Muhammad), tumse pehle humne jo paighambar bhejey thay woh sab bhi Insan hi thay, aur inhi bastiyon ke rehne walon mein se thay, aur unhi ki taraf hum wahee bhejte rahey hain. Phir kya yeh log zameen mein chale phire nahin hain ke un qaumon ka anjaam inhein nazar na aaya jo insey pehle guzar chuki hain? Yaqeenan aakhirat ka ghar un logon ke liye aur zyada behtar hai jinhon ne (paigambaron ki baat maan kar) taqwe ke rawish ikhtiyar ki. Kya ab bhi tum log na samjhogey" },
    { number: 110, arabic: "حَتَّىٰٓ إِذَا ٱسْتَيْـَٔسَ ٱلرُّسُلُ وَظَنُّوٓا۟ أَنَّهُمْ قَدْ كُذِبُوا۟ جَآءَهُمْ نَصْرُنَا فَنُجِّىَ مَن نَّشَآءُ ۖ وَلَا يُرَدُّ بَأْسُنَا عَنِ ٱلْقَوْمِ ٱلْمُجْرِمِينَ", transliteration: "Hatta itha istayasa alrrusulu wathannoo annahum qad kuthiboo jaahum nasruna fanujjiya man nashao wala yuraddu basuna AAani alqawmi almujrimeena", transliterationB: "Hattaaa izas tai'asar Rusulu wa zannooo annahum qad kuziboo jaaa'ahum nas runaa fanujjiya man nashaaa'u wa laa yuraddu baasunna 'anil qawmil mujrimeen", english: "(Respite will be granted) until, when the messengers give up hope (of their people) and (come to) think that they were treated as liars, there reaches them Our help, and those whom We will are delivered into safety. But never will be warded off our punishment from those who are in sin", romanUrdu: "(pehle paigambaron ke saath bhi yahi hota raha hai ke woh muddaton naseehat karte rahey aur logon ne sunkar na diya) yahan tak ke jab paigambar logon se mayous ho gaye aur logon ne bhi samajh liya ke unse jhoot bola gaya tha, to yakayak hamari madad paigambaron ko pahunch gayi .Phir jab aisa mauqa aa jata hai to hamara qaida yeh hai ke jisey hum chahte hain bacha lete hain aur mujrimon par se to hamara azaab taala hi nahin jaa sakta" },
    { number: 111, arabic: "لَقَدْ كَانَ فِى قَصَصِهِمْ عِبْرَةٌۭ لِّأُو۟لِى ٱلْأَلْبَٰبِ ۗ مَا كَانَ حَدِيثًۭا يُفْتَرَىٰ وَلَٰكِن تَصْدِيقَ ٱلَّذِى بَيْنَ يَدَيْهِ وَتَفْصِيلَ كُلِّ شَىْءٍۢ وَهُدًۭى وَرَحْمَةًۭ لِّقَوْمٍۢ يُؤْمِنُونَ", transliteration: "Laqad kana fee qasasihim AAibratun liolee alalbabi ma kana hadeethan yuftara walakin tasdeeqa allathee bayna yadayhi watafseela kulli shayin wahudan warahmatan liqawmin yuminoona", transliterationB: "Laqad kaana fee qasasihim 'ibratul li ulil albaa; maa kaana hadeesany yuftaraa wa laakin tasdeeqal lazee baina yadihi wa tafseela kulli shai'inw wa hudanw wa rahmatal liqawminy yu'minoon", english: "There is, in their stories, instruction for men endued with understanding. It is not a tale invented, but a confirmation of what went before it,- a detailed exposition of all things, and a guide and a mercy to any such as believe", romanUrdu: "Agle logon ke in qisson mein aqal-o-hosh rakhne walon ke liye ibrat hai. Yeh jo kuch Quran mein bayan kiya jaa raha hai yeh banawati baatein nahin hain balke jo kitabein issey pehle aayi hui hain unhi ki tasdeeq hai, aur har cheez ki tafseel aur iman laney walon ke liye hidayat aur rehmat" }
  ]
};
